INSERT INTO `lang_text_name` (`id`, `lang_text`, `lang_code_2a`, `lang_variant`, `text`) VALUES
(1, 1, 'en', NULL, 'Learn about our cookie policy. We describe all the cookies we use on our platform.'),
(2, 1, 'es', NULL, 'Conoce nuestra política de cookies. Describimos todas las cookies que usamos en nuestra plataforma.'),
(3, 2, 'en', NULL, 'Cookies policy'),
(4, 2, 'es', NULL, 'Política de Cookies'),
(5, 3, 'en', NULL, 'Cookies policy'),
(6, 3, 'es', NULL, 'Política de Cookies'),
(7, 4, 'en', NULL, '<div class=\"legal_section_title\">Owner of this website</div>\n                                    <div id = \"legal_identity\">\n                                        <div> Legal entity: <b> Gestión y Desarrollo de Proyectos e Iniciativas, S.L. </b> </div>\n                                        <div> Contact address: <b> Calle Padre Claret, 7, 47004, Valladolid, Spain </b> </div>\n                                        <div> Mail: <b> info@mielsandonis.com </b> </div>\n                                        <div> CIF / NIF: <b> B-67723247 </b> </div>\n                                        <div> Mercantile Registry of Valladolid: <b> 1st entry of page V-32737, to page 167 of volume 1605 </b> </div>\n                                    </div>\n                                    <div class = \"legal_section_title\"> Introduction </div>\n                                    <div class = \"legal_p\">\n                                        The purpose of this cookie policy is to inform you clearly and precisely about the cookies used in the\n                                        website accesme.com.\n                                    </div>\n                                    <div class = \"legal_section_title\"> What are cookies? </div>\n                                    <div class = \"legal_p\">\n                                        A cookie is a small piece of text that the websites you visit send to the browser and that allows the website to\n                                        remember information about your visit, such as your preferred language and other options, in order to facilitate your next visit and\n                                        make the site more useful to you. Cookies play a very important role and contribute to a better experience\n                                        navigation for the user.\n                                        <br/> <br/>\n                                        Contrary to what is popularly believed, cookies by themselves do not constitute any type of risk for your computer.\n                                        nor for your data. Browsers include policies that limit the ability to be consulted from one domain to another, so\n                                        even if they contain sensitive data, only the domain that created it would have access to it.\n                                    </div>\n                                    <div class = \"legal_section_title\"> Types of cookies </div>\n                                    <div class = \"legal_p\">\n                                        Depending on who is the entity that manages the domain from where the cookies are sent and the data obtained is processed, the\n                                        They can distinguish between two types: own cookies and third-party cookies.\n                                        <br/> <br/>\n                                        There is also a second classification according to the period of time that they remain stored in the client\'s browser,\n                                        These may be session cookies or persistent cookies.\n                                        <br/> <br/>\n                                        Finally, there is another classification with five types of cookies according to the purpose for which the data obtained is processed:\n                                        technical cookies, personalization cookies, analysis cookies, advertising cookies and behavioral advertising cookies.\n                                        <br/> <br/>\n                                        For more information in this regard, you can consult the Guide on the use of cookies from the Spanish Agency for Data Protection.\n                                    </div>\n                                    <div class = \"legal_section_title\"> Cookies used on this website </div>\n                                    <div class = \"legal_p\">\n                                        The cookies that are being used in this portal as well as their type and function are identified below:\n                                        <br/> <br/>\n                                        The website accesme.com uses Google Analytics, a web analytics service developed by Google, which allows the\n                                        measurement and analysis of navigation on web pages. In your browser you can see cookies from this service. According to\n                                        The above typology is about own, session and analysis cookies.\n                                        <br/> <br/>\n                                        Through web analytics information is obtained regarding the number of users accessing the web, the number of pages\n                                        views, the frequency and repetition of visits, their duration, the browser used, the operator that provides the service,\n                                        the language, the terminal you use and the city to which your IP address is assigned. Information that enables a better and\n                                        more appropriate service on the part of this portal.\n                                        <br/> <br/>\n                                        To guarantee anonymity, Google will make your information anonymous by truncating the IP address before storing it, accordingly.\n                                        Google Analytics is not used to locate or collect personally identifiable information from site visitors.\n                                        Google may only send the information collected by Google Analytics to third parties when it is legally obliged to do so. With\n                                        According to the conditions of provision of the Google Analytics service, Google will not associate your IP address with any other data\n                                        kept by Google.\n                                        <br/> <br/>\n                                        Another of the cookies that are downloaded is a technical cookie called PHP_SessionId. This cookie allows you to store a\n                                         Unique identifier per session through which it is possible to link data necessary to enable current browsing.\n                                         <br/> <br/>\n                                         Finally, a cookie called ControlCookies, proprietary, technical and session type, is downloaded. Manage consent\n                                         of the user for the use of cookies on the website, in order to remember those users who have accepted and\n                                         those that do not, so that the former are not shown information at the top of the page about it.\n                                     </div>\n                                    <div class = \"legal_section_title\"> Acceptance of the cookie policy </div>\n                                    <div class = \"legal_p\">\n                                        By pressing the \"OK\" button it is assumed that you accept the use of cookies.\n                                    </div>\n                                    <div class = \"legal_section_title\"> How to modify cookie settings </div>\n                                    <div class = \"legal_p\">\n                                        You can restrict, block or delete cookies from accesme.com or any other web page using your browser. In\n                                        Each browser, the operation is different, there are many resources on the internet that will show you how to do it.\n                                    </div>\n                                    <div class = \"legal_section_title\"> Downloads </div>\n                                    <div class = \"legal_p\">\n                                        Guide on the use of cookies from the Spanish Agency for Data Protection:\n                                        <br/> <br/>\n                                        http://www.interior.gob.es/documents/10180/13073/Guia_Cookies.pdf\n                                        <br/> <br/>\n                                        <br/> <br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        C / Padre Claret, 7, 47004 Valladolid Telf: 983 10 59 08 http://mielsandonis.com\n                                    </div>'),
(8, 4, 'es', NULL, '<div class=\"legal_section_title\">Propietario de esta web</div>\n                                    <div id=\"legal_identity\">\n                                        <div>Entidad jurídica: <b>Gestión y Desarrollo de Proyectos e Iniciativas, S.L.</b></div>\n                                        <div>Dirección de contacto: <b>Calle Padre Claret, 7, 47004, Valladolid, España</b></div>\n                                        <div>Mail: <b>info@mielsandonis.com</b></div>\n                                        <div>CIF/NIF: <b>B-67723247</b></div>\n                                        <div>Registro Mercantil de Valladolid: <b>Inscripción 1ª de la hoja V-32737, al folio 167 del tomo 1605</b></div>\n                                    </div>\n                                    <div class=\"legal_section_title\">Introducción</div>\n                                    <div class=\"legal_p\">\n                                        La presente política de cookies tiene por finalidad informarle de manera clara y precisa sobre las cookies que se utilizan en la \n                                        página web mielsandonis.com.\n                                    </div>\n                                    <div class=\"legal_section_title\">¿Qué son las cookies?</div>\n                                    <div class=\"legal_p\">\n                                        Una cookie es un pequeño fragmento de texto que los sitios web que visita envían al navegador y que permite que el sitio web \n                                        recuerde información sobre su visita, como su idioma preferido y otras opciones, con el fin de facilitar su próxima visita y \n                                        hacer que el sitio le resulte más útil. Las cookies desempeñan un papel muy importante y contribuyen a tener una mejor experiencia \n                                        de navegación para el usuario.\n                                        <br/><br/>\n                                        Contrariamente a lo que popularmente se cree las cookies por si mismas no constituyen ningún tipo de riesgo para ni su equipo\n                                        ni para sus datos. Los navegadores incluyen políticas que limitan la capacidad de ser consultadas de un dominio a otro por lo que\n                                        aunque contuvieran datos sensibles sólo el dominio que la ha creado tendría acceso a la misma.\n                                    </div>\n                                    <div class=\"legal_section_title\">Tipos de cookies</div>\n                                    <div class=\"legal_p\">\n                                        Según quién sea la entidad que gestione el dominio desde dónde se envían las cookies y se traten los datos que se obtengan, se \n                                        pueden distinguir dos tipos: cookies propias y cookies de terceros.\n                                        <br/><br/>\n                                        Existe también una segunda clasificación según el plazo de tiempo que permanecen almacenadas en el navegador del cliente, \n                                        pudiendo tratarse de cookies de sesión o cookies persistentes.\n                                        <br/><br/>\n                                        Por último, existe otra clasificación con cinco tipos de cookies según la finalidad para la que se traten los datos obtenidos: \n                                        cookies técnicas, cookies de personalización, cookies de análisis, cookies publicitarias y cookies de publicidad comportamental.\n                                        <br/><br/>\n                                        Para más información a este respecto puede consultar la Guía sobre el uso de las cookies de la Agencia Protección de Datos.\n                                    </div>\n                                    <div class=\"legal_section_title\">Cookies utilizadas en esta web</div>\n                                    <div class=\"legal_p\">\n                                        A continuación se identifican las cookies que están siendo utilizadas en este portal así como su tipología y función:\n                                        <br/><br/>\n                                        La página web mielsandonis.com utiliza Google Analytics, un servicio de analítica web desarrollada por Google, que permite la \n                                        medición y análisis de la navegación en las páginas web. En su navegador podrá observar cookies de este servicio. Según la \n                                        tipología anterior se trata de cookies propias, de sesión y de análisis.\n                                        <br/><br/>\n                                        A través de la analítica web se obtiene información relativa al número de usuarios que acceden a la web, el número de páginas \n                                        vistas, la frecuencia y repetición de las visitas, su duración, el navegador utilizado, el operador que presta el servicio, \n                                        el idioma, el terminal que utiliza y la ciudad a la que está asignada su dirección IP. Información que posibilita un mejor y \n                                        más apropiado servicio por parte de este portal.\n                                        <br/><br/>\n                                        Para garantizar el anonimato, Google convertirá su información en anónima truncando la dirección IP antes de almacenarla, de \n                                        forma que Google Analytics no se usa para localizar o recabar información personal identificable de los visitantes del sitio. \n                                        Google solo podrá enviar la información recabada por Google Analytics a terceros cuanto esté legalmente obligado a ello. Con \n                                        arreglo a las condiciones de prestación del servicio de Google Analytics, Google no asociará su dirección IP a ningún otro dato \n                                        conservado por Google.\n                                        <br/><br/>\n                                        Otra de las cookies que se descargan es una cookie de tipo técnico denominada PHP_SessionId. Esta cookie permite almacenar un \n                                        identificador único por sesión a través del que es posible vincular datos necesarios para posibilitar la navegación en curso.\n                                        <br/><br/>\n                                        Por último, se descarga una cookie denominada ControlCookies, propia, de tipo técnico y de sesión. Gestiona el consentimiento \n                                        del usuario para el uso de las cookies en la página web, con el objeto de recordar aquellos usuarios que las han aceptado y \n                                        aquellos que no, de modo que a los primeros no se les muestre información en la parte superior de la página al respecto.\n                                    </div>\n                                    <div class=\"legal_section_title\">Aceptación de la política de cookies</div>\n                                    <div class=\"legal_p\">\n                                        Pulsando el botón “OK” se asume que usted acepta el uso de cookies.\n                                    </div>\n                                    <div class=\"legal_section_title\">Cómo modificar la configuración de las cookies</div>\n                                    <div class=\"legal_p\">\n                                        Usted puede restringir, bloquear o borrar las cookies de mielsandonis.com o cualquier otra página web utilizando su navegador. En \n                                        cada navegador la operativa es diferente, existen multitud de recursos en internet que le mostrarán cómo hacerlo.\n                                    </div>\n                                    <div class=\"legal_section_title\">Descargas</div>\n                                    <div class=\"legal_p\">\n                                        Guía sobre el uso de las cookies de la Agencia de Protección de Datos:\n                                        <br/><br/>\n                                        http://www.interior.gob.es/documents/10180/13073/Guia_Cookies.pdf\n                                        <br/><br/>\n                                        <br/><br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.                                      \n                                        C/ Padre Claret, 7, 47004 Valladolid Telf: 983 10 59 08  http://mielsandonis.com\n                                    </div>'),
