(31, 16, 'en', NULL, '<div id=\"parts_identification\" class=\"legal_section_title\">Identification of the Parties</div>\n                                    <div class = \"legal_p\">\n                                        These general conditions for contracting the services offered at the URL accesme.com\n                                        (hereinafter the PORTAL) are subscribed, by Gestión y Desarrollo de Proyectos e Iniciativas, S.L., (hereinafter the ENTITY),\n                                        owner of said URL, with address at Calle Padre Claret, number 7, 47004 Valladolid, with C.I.F. No. B-67723247,\n                                        registered in the Mercantile Registry of Valladolid, 1st Inscription of page V-32737, to page 167 of volume 1605 and\n                                        with Telephone 983 10 59 08, email <a href=\"mailto:info@mielsandonis.com\" title=\"\"> info@mielsandonis.com </a>.\n                                        <br /> <br />\n                                        At any time, the interested party may save or print these conditions and the user is advised to do so.\n                                        And, on the other hand, the CLIENT, whose personal data are those that have been consigned by the same in the form that\n                                        the ENTITY has made it available to you.\n                                        <br /> <br />\n                                        All the data included in the aforementioned form have been entered directly by the CLIENT, so the\n                                        Responsibility for the authenticity of the same corresponds, directly and exclusively, to the same.\n                                        </br> </br>\n                                        It is mandatory that you read and understand these general conditions and the information and specific conditions of the product\n                                        that you want to contract or acquire before proceeding with your purchase. You must expressly accept them by clicking on the\n                                        box \"I accept the general contracting conditions\", as well as all those particular conditions collected\n                                        for the use and / or contracting of specific and specific services.\n                                        </br> </br>\n                                        In case of not accepting these General Contracting Conditions, the client must refrain from accessing\n                                        and / or use the services and / or content offered by accesme.com.\n                                        </br> </br>\n                                        This contract will enter into force on the same day of its formalization, will be tacitly extended, and will not be\n                                        finished while the client does not state in writing, with a minimum of 15 days notice and with the indications of\n                                        authentication required by the ENTITY, the cancellation of the same.\n                                    </div>\n                                    <div id=\"legal_definitions\" class = \"legal_section_title\">Definitions</div>\n                                    <div class = \"legal_p\">\n                                        <b> Client </b>: Any natural or legal person who completes the contracting form and chooses one of the\n                                        services offered by Gestión y Desarrollo de Proyectos e Iniciativas, S.L. through its URL accesme.com and that\n                                        It is listed as one of the contracting parties. The ENTITY understands that the service it offers is intended for owners and / or\n                                        managers of web pages and that therefore they are companies in any of their forms, including the self-employed; that is to say\n                                        It is a B2B service (business to business). For this reason, the provisions of Royal Legislative Decree 1/2007 do not apply,\n                                        of November 16, which approves the revised text of the General Law for the Defense of Consumers and Users.\n                                        However, the ENTITY considers it a good company policy to guarantee the withdrawal rights regulated in said standard and\n                                        In this same text, as well as in the Contract Conditions, the forms of its exercise and the deadlines are established.\n                                        <br /> <br />\n                                        <b> Contract </b>: Text that contains all the clauses included in this document, as well as any additional information that,\n                                        on the particular service chosen by the client, it is expressly collected in an updated manner at the URL accesme.com. or\n                                        other URLs owned by Gestión y Desarrollo de Proyectos e Iniciativas, S.L ..\n                                        <br /> <br />\n                                        <b> Commercial content </b>: Information on resources, applications, characteristics and prices of services and / or\n                                        plans that are manifested on the web accesme.com will prevail over what is stated in this contract; for the\n                                        manifested in all aspects not mentioned above (commercial content), the provisions of this\n                                        contract.\n                                        <br /> <br />\n                                        <b> Domain name </b>: Set of characters that identifies a site on the Internet with an address (IP).\n                                        <br /> <br />\n                                        IP (Internet Protocol): set of rules that regulate the transmission of data through the network.\n                                        <br /> <br />\n                                        <b> Services / Plans </b>: Each of the contractable services offered by Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        Through the URL accesme.com that imply some resources and applications of that service / plans that\n                                        offered by accesme.com and which are collected in an updated manner on the company\'s website, accesme.com.\n                                        <br /> <br />\n                                        The services subject to the conditions of this contract are offered as shared services and resources in the\n                                        servers of Gestión y Desarrollo de Proyectos e Iniciativas, S.L., that is, several websites of different clients\n                                        they can be served from the same server, without existing resource exclusivity.\n                                        <br /> <br />\n                                        <b> Resources and Applications </b>: These are the technical and computer programming characteristics provided and supported\n                                        for the different services / plans that the client hires.\n                                        <br /> <br />\n                                        <b> Servers </b>: IT equipment owned or subcontracted by Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        from where the service that the client hires through the services / plans offered by accesme.com is provided.\n                                        <br /> <br />\n                                        <b> Control panel </b>: It is the tool developed Gestión y Desarrollo de Proyectos e Iniciativas, S.L. That\n                                        awards with each of the services / plans for the management by the client of the configurations of which\n                                        has the contracted service, as well as activating other additional services whose prices are determined in a manner\n                                        Updated at accesme.com in those services / plans that allow it.\n                                        <br /> <br />\n                                        It also allows the customer to control the billing data of the customer file, the billing issued to the customer\n                                        Until the date on which you make the query and manage the various contracted services, as well as make additions, cancellations and\n                                        modifications of services. If any of the actions mentioned above are executed, through the control panel\n                                        control, this action will be reflected in the management system of accesme.com, so that each order causes the\n                                        technical and administrative actions necessary for the development of the required action.\n                                        <br /> <br />\n                                        <b> Login and password </b>: It is the system that allows client authentication to access the control panel\n                                        of the client and for the request of aid and information about the contracted service, that is, it is a system that\n                                        guarantees that access to services, contracts, data and customer information is safe, reliable and truthful at all times\n                                        that comes from customers accessme.com uses these systems to identify, authenticate and verify the\n                                        customer person\n                                    </div>\n                                    <div id=\"buying_process\" class=\"legal_section_title\">How to make a purchase</div>\n                                    <div class = \"legal_p\">\n                                        To make a purchase or contract, you must follow the online purchasing procedure offered for each service offered.\n                                         <br /><br />\n                                         You must inform the domain name to which you wish to integrate the service to be contracted from among those offered by the COMPANY on its website and accept the\n                                         Terms of use, Conditions of contract.\n                                         <br /><br />\n                                         Each contracting procedure for our services will request additional information essential for its execution.\n                                         <br /><br />\n                                         In the event that the new contract means the creation of a new account, you will be asked for the essential data to\n                                         the billing of said or future contracts. Among the data requested will be: the client\'s name, address and NIF.\n                                         Additionally, you will be asked for an email address and a password. This data will be used to give you access to the Control Panel from where\n                                         you will be able to manage your account.\n                                         <br /><br />\n                                         Once the contract has been made, regardless of whether it has meant a payment, the COMPANY will send communications via email to the account\n                                         email address provided to inform you of the status of said contract and the instructions so you can make the modifications\n                                         on their website that are accurate.\n                                         <br /><br />\n                                         At that moment it will be considered that the client has contracted the service, the moment this contract comes into force.\n                                         <br/><br/>\n                                         The client has, when the service so stipulates in the particular contracting conditions, a trial/demonstration period of 7 days\n                                         natural periods during which no invoice will be issued and you will have full service.\n                                         <br/><br/>\n                                         Once the end of the trial/demonstration period has arrived, the client will be sent an email message with the instructions to make the payment.\n                                         if it had not been done previously. Once the payment has been made and its receipt has been verified, the client will be able to consult the generated invoice and\n                                         other documentation in the Control Panel made available to you.\n                                    </div>\n                                    <div id=\"services_withdrawal\" class=\"legal_section_title\">Legal right to withdraw from the purchase</div>\n                                     <div class=\"legal_p\">\n                                         Right of withdrawal\n                                         <br/><br/>\n                                         You are contracting as a consumer and user, you have the right to withdraw from this contract within a period of 14 calendar days without the need for justification.\n                                         <br/><br/>\n                                         You may withdraw from those services that do not involve personalized work for a specific website or web page already carried out, nor from those services.\n                                         that its result is a deliverable that has already been delivered, for example a report or some modifications to a document.\n                                         <br/><br/>\n                                         The withdrawal period will expire 14 calendar days from the day on which you or a third party indicated by you, contracted our services. You must exercise your\n                                         right to withdraw from each service separately and independently.\n                                         <br/><br/>\n                                         To exercise the right of withdrawal you must notify us from the email address provided as a notification email to our contact email published in\n                                         our portal.\n                                         <br/><br/>\n                                         To comply with the withdrawal period, it is enough for the communication regarding your exercise of this right to be sent before it expires.\n                                         the corresponding term.\n                                         <br/><br/>\n                                         In case of withdrawal on your part, we will return all payments received from you, including expenses without any undue delay and,\n                                         In any case, no later than 14 calendar days from the date on which we are informed of your decision to withdraw from this contract.\n                                         We will proceed to make said refund using the same payment method used by you for the initial transaction, unless you tell us otherwise.\n                                         Otherwise, expressly detailing the payment method through which you want us to make the return. You will not incur any expenses as a result of the\n                                         refund.\n                                     </div>\n                                    <div id=\"services_offered\" class=\"legal_section_title\">Purpose and definition of the services offered</div>\n                                    <div class=\"legal_p\">\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L. offers a tool through the URL cdn.access-me.software that once integrated into\n                                        the client\'s website will modify this in such a way that it will add the necessary elements to adapt it to the recognized accessibility guides\n                                        internationally. It will also integrate a tool (widged) that will allow the user / visitor of the client\'s website to select one or more\n                                        Settings that will also modify the client\'s website to adapt it to the visitor\'s needs.\n                                        <br/> <br/>\n                                        Therefore, the conditions contained in this contract will be applicable to the services / plans listed on the web, likewise, this\n                                        The contract will be applied to all services / plans created and developed by Gestión y Desarrollo de Proyectos e Iniciativas, S.L. and offered by the web\n                                        accesme.com that meets the characteristics on the ENTITY\'s website.\n                                        <br/> <br/>\n                                        The technical characteristics of each of these services / plans, as well as the price to be paid for them comes, at all times,\n                                        clearly determined on the corresponding services / plans page of accesme.com. In any case, the resources and applications that\n                                        Each service / plan provides will be those that are published on the web at all times, accesme.com.\n                                        <br/> <br/>\n                                        The operation of each service / plan necessarily implies having the ownership of a generic top-level domain name (gTLD)\n                                        or territorial (ccTLD).\n                                        Domain name registration can be done through any provider.\n                                                                                <br/> <br/>\n                                        The services are activated with automatic renewal, to deactivate it the client must access their Control Panel with at least fifteen days (15d)\n                                        in advance of its expiration date and request it by pressing the button provided for this purpose. Said automatic renewal will be carried out at\n                                        Date of Expiry.\n                                        <br/> <br/>\n                                        The costs of the plans will be those set on the website owned by the ENTITY at all times and for each type of service / plan.\n                                        <br/> <br/>\n                                        The services / plans that are the object of this contract are composed, among other resources, of a tool called \"control panel\" for each\n                                        client, from which the client can manage and administer the resources and applications of the server / plan to which it refers.\n                                        <br/> <br/>\n                                        The possibility is offered to the client who has contracted a service / plan at accesme.com that can change to another service / plan at accesme.com\n                                        Either with characteristics, resources and applications superior to the service / plan that you already have or inferior.\n                                        <br/> <br/>\n                                        The change will be made from the customer\'s Control Panel.\n                                        <br/> <br/>\n                                        Once a change in services / plans has been made, another change of service / plan cannot be requested within a period of thirty days (30d) from\n                                        since the last change was made.\n                                        <br/> <br/>\n                                        If the change is made to a higher plan in features, resources and applications, a credit or debit will be generated for the amount paid.\n                                        and not consumed or vice versa that will be credited or charged in the next invoice that is issued to the customer as appropriate.\n                                    </div>\n                                    <div id=\"legal_updates\" class=\"legal_section_title\">Modifications</div>\n                                    <div class=\"legal_p\">\n                                        The portal reserves the right to modify, limit or cancel all or any of the applicable terms and conditions\n                                        to the aforementioned web site, as long as a notice is made at least 15 days in advance.\n                                        The notice will be made through a pop-up window, which will open when accessing the page, or a notification to the user\n                                        which will be carried out prior to the modification, limitation or cancellation.\n                                        <br/> <br/>\n                                        The client, once the modification has been communicated by accesme.com, has a period of 15 days, from the moment they receive\n                                        said communication, to terminate the contract if you do not agree with the new circumstances, after this period\n                                        Without communication to the contrary from the client, it will be understood that he accepts the new conditions.\n                                    </div>\n                                    <div id=\"portal_uses\" class=\"legal_section_title\">Conditions of access and use of the portal</div>\n                                    <div class=\"legal_p\">\n                                        <b> Characteristics of the service offered </b>\n                                        <br/> <br/>\n                                        Registration in the services / plans of accesme.com and access to the control panel corresponding to the contracted service is free.\n                                        The provision of the service that gives rise to this contract is onerous, and the client must pay in advance to\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L. the price (including the appropriate tax) corresponding to\n                                        each service determined on the web.\n                                        <br/> <br/>\n                                        The ENTITY will issue the corresponding invoice with details of all the concepts that make up said services.\n                                        <br/> <br/>\n                                        The benefits included in each of the different services offered by the ENTITY, including price, mode and\n                                        Payment terms are defined in detail on the website.\n                                        <br/> <br/>\n                                        Paid services will be distinguished from free ones by indicating their price on the rates and services pages,\n                                        being an essential condition, click on the \"contract\" icon and fill in the contracting form that will prove\n                                        acceptance of economic conditions.\n                                        <br/> <br/>\n                                        The entity reserves the right to charge an additional fee in the event of a bank refund of 5.17 euros (plus VAT) or\n                                        of 10% on amounts over 100 euros, and to temporarily block access to the customer\'s Control Panel before\n                                        any incident in the collection, until the resolution of the same and is up to date with payment.\n                                        <br/> <br/>\n                                        In case of not paying the invoice for the service provided, the company reserves the right to include your data in files\n                                        known as delinquency for example the \"Asnef\" of EQUIFAX IBÉRICA, S.L, which will be withdrawn once verified that\n                                        the invoice has been paid.\n                                        <br/> <br/>\n                                        THE ENTITY reserves the right to apply a penalty derived from the expenses generated by the opening of the file\n                                        idic, which will not exceed 50 euros in any case.\n                                        <br/> <br/>\n                                        Every client will select one of the services offered, this operation being the contracting element of the service that\n                                        carries with it the obligation of prior registration.\n                                        <br/> <br/>\n                                        Thus, THE ENTITY may modify the client name, password and security code, prior notice to the user via\n                                        email.\n                                        <br/> <br/>\n                                        The resources and applications used by the contracted service can be activated or deactivated at any time while the\n                                        service is active and current with payment; Now, if a resource or application has an extra monthly cost, the fact\n                                        Deactivating it before the month paid in advance expires does not imply the refund of the proportional part not consumed.\n                                        <br/> <br/>\n                                        The users of services who do not carry out the contracting will also be bound by the regulatory conditions of the portal.\n                                        <br/> <br/>\n                                        <b> Technical access requirements </b>\n                                        <br/> <br/>\n                                        To access the Portal, the User must have access to the Internet, pay the access and connection fees\n                                        and have the equipment and computer systems necessary to connect to the Network, including\n                                        a terminal that is suitable for the purpose (computer, telephone, etc.) and a modem or other similar or similar access device.\n                                        <br/> <br/>                                        \n                                        For the correct access and use of certain contents and services of the Portal, it implies the download in your computer equipment of\n                                        certain computer programs or other logical elements. Said installation will be borne by the User, declining the COMPANY\n                                        any type of liability that may arise from it.\n                                        <br/> <br/>\n                                        <b> Obligation to make correct use of the Portal and the Services </b>\n                                        <br/> <br/>\n                                        The User agrees to use the Portal, the Services, and these General Conditions in accordance with the law, morality,\n                                        good manners and public order.\n                                        <br/> <br/>\n                                        The User undertakes to refrain from using the Portal and the Services for illicit purposes or effects, contrary to those established\n                                        in these General Conditions; harmful to the rights and interests of third parties, or that in any way may damage, disable,\n                                        overload or deteriorate the Portal and / or the Services, or prevent the normal use or enjoyment of the Portal and / or the Services by\n                                        part of the Users.\n                                        <br/> <br/>\n                                        <b> Denial and withdrawal of access to the Portal and / or Services </b>\n                                        <br/> <br/>\n                                        THE ENTITY reserves the right to deny or withdraw access to the Portal and / or the Services, at any time and without the need to\n                                        prior notice to those Users who violate these General Conditions or violate any of the precepts established by the\n                                        Law of Services of the Information Society and Electronic Commerce (LSSICE) or equivalent legislation.\n                                        <br/> <br/>\n                                        <b> Correct use of the Contents </b>\n                                        <br/> <br/>\n                                        The client:\n                                        <br/>\n                                        The Client undertakes to use the Contents in a diligent, correct and lawful manner and, in particular, undertakes to refrain from:\n                                        <br/> <br/>\n                                            Use the Contents in a way, for purposes or effects contrary to the law, morality and generally good customs\n                                            accepted or public order;\n                                        <br/> <br/>\n                                            Reproduce or copy, distribute, allow public access through any form of public communication,\n                                            transform or modify the Contents, unless you have the authorization of the owner of the corresponding rights or\n                                            this is legally permitted;\n                                        <br/> <br/>\n                                            Delete, evade or manipulate the \"copyright\" and other identifying data of the rights of THE ENTITY or its owners\n                                            incorporated into the Contents, as well as the technical protection devices, or any information mechanisms that\n                                            may contain the Contents.\n                                            <br/> <br/>\n                                        The portal:\n                                        <br/>\n                                        THE ENTITY does not control or guarantee the absence of viruses or other elements in the Contents that may cause alterations in\n                                        your computer system (software and hardware) or in the electronic documents and files stored in your computer system.\n                                        <br/> <br/>\n                                        <b> Use of the Services </b>\n                                        <br/> <br/>\n                                        The use of the Services offered on the Portal of THE ENTITY in accordance with the Non-Consent Advertising Policy regulated in\n                                        the Law of Services of the Information Society and Electronic Commerce (LSSICE):\n                                        <br/> <br/>\n                                        The User and the Portal are obliged to make use of the Services in accordance with the Non-Consent Advertising Policy, and in particular,\n                                        undertakes to:\n                                        <br/> <br/>\n                                        Do not send chains of unsolicited electronic messages.\n                                        <br/> <br/>\n                                        In the cases of sending advertising by THE ENTITY, the Users will be sent with the word \"advertising\" so as not to\n                                        mislead.\n                                        <br/> <br/>\n                                        Users harmed by the receipt of unsolicited messages addressed to a plurality of people may communicate it to\n                                        THE ENTITY sending a message to the email account: <a href=\"mailto:info@mielsandonis.com\" title=\"Send mail\"> info@mielsandonis.com </a>.\n                                    </div>\n                                    <div id=\"responsibilities\" class=\"legal_section_title\">Responsibilities</div>\n                                    <div class=\"legal_p\">\n                                        From the portal:\n                                        <br/>\n                                        It will not be responsible, in addition to the responsibilities indicated in the fourth clause of these conditions\n                                        general terms of use on the portal, directly or indirectly from:\n                                        </br> </br>\n                                        The quality of the service, the speed of access, the correct operation, the availability or continuity of\n                                        operation of the portal.\n                                        </br> </br>\n                                        Damage that may be caused to the user\'s equipment by the use of the portal.\n                                        </br> </br>\n                                        Failure to comply with the law, morals and generally accepted good customs or public order as\n                                        consequence of the transmission, diffusion, storage, making available, reception, obtaining or access to the\n                                        contents.\n                                        </br> </br>\n                                        The vices and defects of all kinds of the content transmitted, disseminated, stored or made available.\n                                        </br> </br>\n                                        The ENTITY does not own the domains or the websites found in the database.\n                                        </br> </br>\n                                        In addition, the ENTITY does not guarantee that the domain can be used by the client without implying the violation.\n                                        rights of third parties.\n                                        </br> </br>\n                                        The portal cannot guarantee that the availability of the service will be continuous and uninterrupted during the period of\n                                        validity of the contract, due to the possibility of problems in the Internet network, breakdowns in server equipment and\n                                        other possible unforeseeable contingencies.\n                                        </br> </br>\n                                        The client agrees to bear, within reasonable limits, risks and imperfections or unavailability of the servers,\n                                        the programs used are technically complex and may not have been previously tested on all\n                                        possibilities that exist of use.\n                                        </br> </br>\n                                        Therefore, the client expressly waives to claim any responsibility, contractual or extra-contractual, damages and\n                                        Damages to the ENTITY due to possible failures, slowness or errors in the access and use of the contracted Server.\n                                        </br> </br> Although the ENTITY makes backup copies of the content of the servers used to offer the services, it does not\n                                        is responsible for the loss or accidental deletion of data. Similarly, the ENTITY does not guarantee full replacement\n                                        of this data because, in the time elapsed between the last copy and deletion, the data may have changed.\n                                        <br/><br/>\n                                        THE ENTITY is not responsible:\n                                        </br></br>\n                                        Of the errors produced by the access providers.\n                                        </br></br>\n                                        Of virus contamination in the equipment whose protection is incumbent on the client.\n                                        </br></br>\n                                        Of the intrusions of third parties in the client\'s service, although the ENTITY has established reasonable protection measures.\n                                        </br></br>\n                                        Of the faulty configuration by the client.\n                                        </br></br>\n                                        Of the deterioration of the equipment (customer terminals) or misuse (customer responsibility).\n                                        </br></br>\n                                        The client\'s:\n                                        <br/><br/>\n                                        The client will be responsible:\n                                        </br></br>\n                                        Of the contents entered by them, especially the data and information entered in the form.\n                                        </br></br>\n                                        From the performance of any type of illicit action, harmful to rights, harmful and/or detrimental.\n                                        </br></br>\n                                        The user undertakes not to insert names of domains or websites that already exist in the database, whose name or\n                                        content violate applicable laws.\n                                        </br></br>\n                                        The client undertakes to keep the e-mail address provided in the application form operative, active and up-to-date.\n                                        contracting for communications with the ENTITY since it constitutes the preferred means of communication for the management\n                                        agile and fluid in the provision of the requested service as a result of the contractual relationship that through this\n                                        contract binds us\n                                    </div>\n                                    <div id=\"termination\" class=\"legal_section_title\">Termination of the contract</div>\n                                    <div class=\"legal_p\">\n                                        The contract will end when, in addition to the legally established causes, any of the following concur:\n                                        </br> </br>\n                                        Mutual agreement of the parties.\n                                        </br> </br>\n                                        End of the initial period of duration or of the successive extensions.\n                                        </br> </br>\n                                        Resolution for breach of any of the parties of the obligations derived from the Contract.\n                                        </br> </br>\n                                        When either party is in a situation of bankruptcy or suspension of payments.\n                                        </br> </br>\n                                        If the termination of the contract is due to the breach of the client, the ENTITY reserves the right to terminate the\n                                        anticipated this contract and, therefore, to deprive the client of the contracted service without prior notice and without the\n                                        client has the right to compensation or a refund of any amount.\n                                        <br/> <br/>\n                                        Likewise, if the ENTITY carries out a change in the prices of the services, the clients will be notified, via email, such\n                                        modification before they are affected by the variation in the next invoice issued to them, so that if not\n                                        agrees to accept said change exercise the right to terminate this contract without having to pay\n                                        any additional amount to the ENTITY while keeping your fee paid.\n                                        At the end of the advance payment term, the contract will be terminated and, therefore, your service will be terminated if\n                                        maintained in its non-acceptance of the new price.\n                                    </div>\n                                    <div id=\"privacy_policy\" class=\"legal_section_title\">Privacy Policy</div>\n                                    <div class=\"legal_p\">\n                                        Responsible for the Treatment: Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        <br/> <br/>\n                                        End of treatment:\n                                        <br/> <br/>\n                                        Manage your registration as a client, the provision and administration of the contracting and billing service.\n                                        <br/> <br/>\n                                        Conducting surveys on the degree of satisfaction with the care received.\n                                        <br/> <br/>\n                                        Sending advertising and other commercial promotions by email, SMS, MMS or any other similar means.\n                                        <br/> <br/>\n                                        Data communication:\n                                        <br/> <br/>\n                                        No data will be communicated to third parties except for those entities related to Project Management and Development and\n                                        Initiatives, S.L. for the correct provision of the contracted service and those legally established.\n                                        <br/> <br/>\n                                        <br/> <br/>\n                                        Rights that assist the Interested Party:\n                                        <br/> <br/>\n                                        Right to withdraw consent at any time.\n                                        <br/> <br/>\n                                        Right of access, rectification, portability and deletion of your data and the limitation or opposition to its treatment.\n                                        <br/> <br/>\n                                        Right to file a claim with the Control Authority (agpd.es) if you consider that the treatment does not comply with the\n                                        regulations in force.\n                                        <br/> <br/>\n                                        Contact information to exercise your rights:\n                                        <br/> <br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.,\n                                        <br/>\n                                        C / Padre Claret, 7, 47004 Valladolid or by email to <a href=\"mailto:juridico@mielsandonis.com\" title=\"Send mail\"> juridico@mielsandonis.com </a>,\n                                        along with valid proof in law, such as a photocopy of the D.N.I. and indicating in the subject \"DATA PROTECTION\".\n                                        <br/> <br/>\n                                        Additional information: Document \"Additional Data Protection Information\" available on our website\n                                        <a href=\"https://www.mielsandonis.com\" title=\"Home Access Me\"> https://mielsandonis.com </a>.\n                                        <br/> <br/>\n                                        The interested party consents to the processing of the data in the terms set forth.\n                                    </div>\n                                    <div id=\"third_parties\" class=\"legal_section_title\">What happens if the contracted service involves access by third parties?</div>\n                                    <div class=\"legal_p\">\n                                        If for the provision of the services contracted through the web and, specifically regarding the treatment of the data of the\n                                        Customer staff refers, Gestión y Desarrollo de Proyectos e Iniciativas, S.L. holds the figure of\n                                        MANAGER OF THE TREATMENT and that of RESPONSIBLE FOR THE TREATMENT.\n                                        <br/> <br/>\n                                        That in compliance with the provisions of article 28 of the GDPR, the MANAGER offers sufficient guarantees to implement\n                                        appropriate technical and organizational policies to apply the security measures established by current regulations and protect\n                                        the rights of the interested parties, for which both parties agree to sign this contract subject to the following\n                                        INSTRUCTIONS FOR DATA PROCESSING:\n                                        <br/> <br/>\n                                        The treatment will consist of the services of adding accessibility to the clients\' websites.\n                                        <br/> <br/>\n                                        Specifically, the following treatments will be carried out:\n                                        <br/> <br/>\n                                        For the execution of the services derived from the fulfillment of the object of this order, the person in charge of the treatment,\n                                        You can make personal data available to the person in charge of the treatment.\n                                        <br/> <br/>\n                                        The person in charge of the treatment and all the personnel of it are obliged to:\n                                        <br/> <br/>\n                                        Use the personal data that is the object of treatment, or those collected for inclusion, only for the purpose of this order.\n                                        In no case may you use the data for your own purposes.\n                                        <br/> <br/>\n                                        Treat the data in accordance with the instructions of the person responsible for the treatment. If the person in charge of the treatment considers that any\n                                        of the instructions violates the RGPD or any other provision on data protection of the Union or of the States\n                                        members, the manager will immediately inform the manager.\n                                        <br/> <br/>\n                                        Do not communicate the data to third parties, unless you have the express authorization of the person responsible for the treatment, in the\n                                        legally admissible assumptions.\n                                        <br/> <br/>\n                                        Do not subcontract any of the services that are part of the object of this contract that involve data processing\n                                        personal, except the auxiliary services necessary for the normal operation of the services of the person in charge.\n                                        If it is necessary to subcontract any treatment, this fact must be communicated previously and in writing to the person in charge, with a\n                                        15 days in advance, indicating the treatments to be subcontracted and clearly and unequivocally identifying the company\n                                        subcontractor and their contact details. Subcontracting may be carried out if the person in charge does not express his opposition in the\n                                        deadline. The subcontractor, who will also be in charge of the treatment, is also obliged to comply with\n                                        the obligations established in this document for the person in charge of the treatment and the instructions issued by the person in charge.\n                                        It is the responsibility of the initial manager to regulate the new relationship so that the new manager is subject to the same conditions\n                                        (instructions, obligations, security measures ...) and with the same formal requirements as him, regarding the appropriate\n                                        processing of personal data and the guarantee of the rights of the affected persons.\n                                        In the event of non-compliance by the sub-manager, the initial manager will remain fully responsible to the manager.\n                                        regarding the fulfillment of obligations.\n                                        <br/><br/>\n                                        Maintain the duty of secrecy regarding the personal data to which you have had access by virtue of this order,\n                                        even after your object ends.\n                                        <br/> <br/>\n                                        Guarantee that the persons authorized to process personal data undertake, expressly and in writing, to respect the\n                                        confidentiality and to comply with the corresponding security measures, of which they must be properly informed.\n                                        <br/> <br/>\n                                        Keep at the disposal of the person in charge the supporting documentation of the fulfillment of the obligation established in the section\n                                        previous.\n                                        <br/> <br/>\n                                        Guarantee the necessary training in the protection of personal data of the persons authorized to process personal data.\n                                        <br/> <br/>\n                                        When the affected persons exercise the rights of access, rectification, deletion and opposition, limitation of treatment,\n                                        data portability and not to be the subject of automated individualized decisions, before the person in charge of the treatment, he must\n                                        communicate it by email to the contact address between both companies. Communication must be done immediately\n                                        and in no case beyond the business day following the receipt of the request, together, where appropriate, with other\n                                        information that may be relevant to resolve the request.\n                                        <br/> <br/>\n                                        Right of information. It is the responsibility of the person responsible to facilitate the right to information at the time of data collection.\n                                        <br/> <br/>\n                                        Notification of data security breaches. The person in charge of the treatment will notify the person in charge of the treatment,\n                                        without undue delay, and in any case before the maximum period of 24 hours, and through the contact email between\n                                        both companies, the violations of the security of the personal data in their charge of which they have knowledge, together with all\n                                        the relevant information for the documentation and communication of the incident.\n                                        Notification will not be necessary when it is unlikely that said breach of security constitutes a risk to the rights and\n                                        the freedoms of natural persons.\n                                        <br/> <br/>\n                                        If available, at least the following information will be provided:\n                                        <br/> <br/>\n                                        Description of the nature of the violation of the security of personal data, including, when possible, the categories\n                                        and the approximate number of affected interested parties, and the categories and approximate number of personal data records affected.\n                                        <br/> <br/>\n                                        The name and contact details of the data protection officer or other contact point where more can be obtained\n                                        information.\n                                        <br/><br/>\n                                        Description of the possible consequences of the violation of the security of personal data.\n                                        <br/> <br/>\n                                        Description of the measures adopted or proposed to remedy the violation of the security of personal data,\n                                        including, if applicable, the measures adopted to mitigate possible negative effects. If it is not possible to facilitate the\n                                        information simultaneously, and to the extent that it is not, the information will be provided gradually without undue delay.\n                                        <br/> <br/>\n                                        Support the data controller in carrying out impact assessments related to data protection,\n                                        when appropriate.\n                                        <br/> <br/>\n                                        Support the data controller in conducting prior consultations with the control authority, when appropriate.\n                                        <br/> <br/>\n                                        Make available to the person in charge all the information necessary to demonstrate compliance with its obligations, as well as for the\n                                        performance of audits or inspections carried out by the person in charge or another auditor authorized by him.\n                                        <br/> <br/>\n                                        Implement the following security measures (depending on the contracted service):\n                                        <br/> <br/>\n                                        Classification of security incidents with their corresponding response and recovery times according to ISO 27001 requirements.\n                                        <br/> <br/>\n                                        Backup mechanisms, fault tolerance and recovery times.\n                                        <br/> <br/>\n                                        Business continuity plans before natural disasters.\n                                        <br/> <br/>\n                                        Organization and structure of data centers has redundancies at the storage, processing, network and power levels\n                                        electrical.\n                                        <br/> <br/>\n                                        Physical and logical access control measures and authentication mechanisms.\n                                        <br/> <br/>\n                                        Vulnerability scans on managed services and on computers that are part of the infrastructure regularly.\n                                        <br/> <br/>\n                                        Safe procedures for accessing the interface, with authentication methods, access restrictions and privileges.\n                                        <br/> <br/>\n                                        In the event of a security incident, it is possible to trace it through the appropriate monitoring procedures.\n                                        <br/> <br/>\n                                        The data centers are located in the European Union. <br/> <br/>\n                                        <br/> <br/>\n                                        In any case, you must implement mechanisms to:\n                                        <br/> <br/>\n                                        Guarantee the confidentiality, integrity, availability and permanent resilience of the treatment systems and services.\n                                        <br/> <br/>\n                                        Restore the availability and access to personal data quickly, in the event of a physical or technical incident.\n                                        <br/> <br/>\n                                        Verify, evaluate and assess, on a regular basis, the effectiveness of the technical and organizational measures implemented to guarantee the\n                                        treatment security.\n                                        <br/> <br/>\n                                        Pseudonymize and encrypt personal data, if applicable.\n                                        <br/> <br/>\n                                        Destroy the data, once the provision has been completed. However, the person in charge may keep a copy, with the data duly\n                                        gasped, as long as responsibilities may arise from the execution of the provision.\n                                    </div>\n                                    <div id=\"property_intellectual\" class=\"legal_section_title\">Property Intellectual and Industrial</div>\n                                    <div class=\"legal_p\">\n                                        The entirety of this website: text, images, brands, graphics, logos, buttons, software files, color combinations,\n                                        as well as the structure, selection, arrangement and presentation of its contents, is protected by the laws on Property\n                                        Intellectual and Industrial, being prohibited its reproduction, distribution, public communication and transformation,\n                                        except for personal and private use.\n                                        <br/> <br/>\n                                        Likewise, the total or partial reproduction, retransmission, copy, assignment or redistribution of the information contained is prohibited.\n                                        on these pages, whatever its purpose and the means used for it.\n                                    </div>\n                                    <div id=\"cookie\" class = \"legal_section_title\">Use of cookie technology and storage in the browser </div>\n                                    <div class = \"legal_p\">\n                                        THE ENTITY reserves the right to use so-called \"cookies\" and other storage technologies for\n                                        information, in any type of use of the Portal.\n                                        <br/> <br/>\n                                        However, Users are informed of the possibility of discarding this use in their computer terminal.\n                                        <br/> <br/>\n                                        <br/> <br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        C / Padre Claret, 7, 47004 Valladolid Telf: 983 10 59 08 http://mielsandonis.com\n                                    </div>');
INSERT INTO `lang_text_name` (`id`, `lang_text`, `lang_code_2a`, `lang_variant`, `text`) VALUES
(32, 16, 'es', NULL, '<div id=\"parts_identification\" class=\"legal_section_title\">Identificación de las Partes</div>\n                                    <div class=\"legal_p\">\n                                        Las presentes condiciones generales de contratación de los servicios ofrecidos en la URL mielsandonis.com \n                                        (en adelante el PORTAL) son suscritas, por Gestión y Desarrollo de Proyectos e Iniciativas, S.L., (en adelante la ENTIDAD),\n                                        titular de dicha URL, con domicilio en Calle Padre Claret, número 7, 47004 Valladolid, con C.I.F. nº B-67723247,\n                                        inscrita en el Registro Mercantil de Valladolid,Inscripción 1ª de la hoja V-32737, al folio 167 del tomo 1605 y \n                                        con Teléfono 983 10 59 08, correo electrónico <a href=\"mailto:info@mielsandonis.com\" title=\"\">info@mielsandonis.com</a>.\n                                        <br /><br />\n                                        En cualquier momento, el interesado podrá guardar o imprimir estas condiciones y se aconseja al usuario a hacerlo. \n                                        Y, de otra parte, el CLIENTE, cuyos datos personales son los que han sido consignados por el mismo en el formulario que\n                                        la ENTIDAD ha puesto a su disposición.\n                                        <br /><br />\n                                        Todos los datos incluidos en el mencionado formulario han sido introducidos directamente por el CLIENTE, por lo que la \n                                        responsabilidad sobre la autenticidad de los mismos corresponde, directa y exclusivamente, al mismo.\n                                        </br></br>\n                                        Es obligatorio que lea y entienda estas condiciones generales y la información y condiciones específicas del producto \n                                        que quiere contratar o adquirir antes de proceder a su compra. Debe aceptarlas expresamente mediante un \"clic\" en la \n                                        casilla \"Acepto las condiciones generales de contratación\", así como todas aquellas condiciones particulares recogidas \n                                        para la utilización y/o contratación de servicios determinados y concretos. \n                                        </br></br>\n                                        En caso de no aceptar las presentes Condiciones Generales de contratación, el cliente deberá abstenerse de acceder\n                                        y/o utilizar los servicios y/o contenidos ofertados por mielsandonis.com.\n                                        </br></br>\n                                        El presente contrato entrará en vigor el mismo día de su formalización, se prorrogará tácitamente, y no se dará por \n                                        finalizado mientras el cliente no manifieste por escrito, con una antelación mínima de 15 días y con las indicaciones de\n                                        autentificación exigidos por la ENTIDAD, la baja del mismo.\n                                    </div>\n                                    <div id=\"legal_definitions\" class=\"legal_section_title\">Definiciones</div>\n                                    <div class=\"legal_p\">\n                                        <b>Cliente</b>: Toda aquella persona física o jurídica que cumplimenta el formulario de contratación y elige alguno de los \n                                        servicios ofrecidos por Gestión y Desarrollo de Proyectos e Iniciativas, S.L. a través de su URL mielsandonis.com y que \n                                        figura como una de las partes contratantes. La ENTIDAD entiende que el servicio que ofrece está destinado a propietarios y/o\n                                        gestores de páginas web y que por lo tanto se trata de empresas en cualquiera de sus formas, incluídos los autónomos; es decir \n                                        es un servicio B2B (bussines to bussines). Por ello no es de aplicación lo recogido en el Real Decreto Legislativo 1/2007, \n                                        de 16 de noviembre, por el que se aprueba el texto refundido de la Ley General para la Defensa de los Consumidores y Usuarios.\n                                        Sin embargo, la ENTIDAD considera una buena política de empresa garantizar los derechos de desistimiento regulados en dicha norma y\n                                        en este mismo texto así como en las Condiciones de contratación se establecen las formas de su ejercicio y los plazos. \n                                        <br /><br />\n                                        <b>Contrato</b>: Texto que contiene todas las cláusulas recogidas en este documento, así como toda información adicional que, \n                                        sobre el servicio particular elegido por el cliente, se recoge de manera actualizada expresamente en la URL mielsandonis.com. u \n                                        otras URLs propiedad de Gestión y Desarrollo de Proyectos e Iniciativas, S.L..\n                                        <br /><br />\n                                        <b>El contenido comercial</b>: La información sobre recursos, aplicaciones, características y precios de los servicios y/o \n                                        planes que se manifiestan en la web mielsandonis.com prevalecerá sobre lo recogido en este contrato; para lo \n                                        manifestado en todos los aspectos no mencionados anteriormente (contenido comercial) prevalecerá lo dispuesto en este \n                                        contrato.\n                                        <br /><br />\n                                        <b>Nombre de dominio</b>: Conjunto de caracteres que identifica un sitio de la red Internet con una dirección (IP).\n                                        <br /><br />\n                                        IP (Internet Protocolo): conjunto de reglas que regulan la transmisión de datos a través de la red.\n                                        <br /><br />\n                                        <b>Servicios/Planes</b>: Cada uno de los servicios contratables ofrecidos por Gestión y Desarrollo de Proyectos e Iniciativas, S.L. \n                                        a través de la URL mielsandonis.com que implixcan unos recursos y aplicaciones propios de ese servicio/planes que \n                                        ofrece mielsandonis.com y que se recogen de manera actualizada en la página web de la empresa, mielsandonis.com.\n                                        <br /><br />                                         \n                                        Los servicios sometidos a las condiciones de este contrato se ofrecen como servicios y recursos compartido en los \n                                        servidores de Gestión y Desarrollo de Proyectos e Iniciativas, S.L., es decir, varios sitios web de diferentes clientes \n                                        pueden ser servidos desde mismo servidor, sin existir exclusividad de recursos.\n                                        <br /><br />\n                                        <b>Recursos y Aplicaciones</b>: Son las características técnicas y de programación informática facilitadas y soportadas \n                                        por los distintos servicios/planes que el cliente contrate.\n                                        <br /><br />\n                                        <b>Servidores</b>: Equipos informáticos propiedad de o subcontratados por Gestión y Desarrollo de Proyectos e Iniciativas, S.L. \n                                        desde donde se suministra el servicio que el cliente contrata a través de los servicios/planes ofrecidos por mielsandonis.com.\n                                        <br /><br />\n                                        <b>Panel de control</b>: Es la herramienta desarrollada Gestión y Desarrollo de Proyectos e Iniciativas, S.L. que se \n                                        adjudica con cada uno de los servicios/planes para la gestión por parte del cliente de las configuraciones de los que \n                                        dispone el servicio contratado, así como incluso activar otros servicios adicionales cuyos precios se determinan de manera \n                                        actualizada en mielsandonis.com en aquellos servicios/planes que lo permitan.\n                                        <br /><br />\n                                        Así mismo le permite al cliente controlar  los  datos  de facturación de la ficha de cliente, la facturación emitida al cliente \n                                        hasta la fecha en la que realiza la consulta y gestionar los diversos servicios contratados, así como efectuar altas, bajas y \n                                        modificaciones de los servicios. Si se ejecuta cualquiera de las acciones mencionadas anteriormente, a través del panel de\n                                        control, quedará reflejada dicha acción en el sistema de gestión de mielsandonis.com, de manera que cada orden provoque las \n                                        actuaciones técnicas y administrativas necesarias para el desarrollo de la acción requerida.\n                                        <br /><br />\n                                        <b>Login y contraseña</b>: Es el sistema que permite la autentificación del cliente para el acceso al panel de control \n                                        del cliente y para la solicitud de ayudas e información sobre el servicio contratado, es decir, se trata de un sistema que \n                                        garantiza que el acceso a los servicios contratos, datos e información del cliente sea segura, fiable y veraz siempre \n                                        que provenga de los clientes mielsandonis.com se sirve de estos sistemas para identificar, autentificar y verificar la \n                                        persona del cliente.\n                                    </div>\n                                    <div id=\"buying_process\" class=\"legal_section_title\">Como se realiza una compra</div>\n                                    <div class=\"legal_p\">\n                                        Para realizar una compra o contratación, deberá seguir el procedimiento de compra online ofrecido para cada servicio ofertado.\n                                        <br /><br />\n                                        Deberá informar el nombre de dominio al que desee integrar el servicio a contratar de entre los ofrecidas por la EMPRESA en su página web y aceptar los\n                                        Términos de uso, Condiciones de contratación.\n                                        <br /><br />\n                                        Cada procedimiento de contratación de nuestros servicios le solicitará información adicional indispensable para su ejecución.\n                                        <br /><br />\n                                        En el caso de que la nueva contratación signifique la creación de una nueva cuenta, se le solicitarán los datos inpescindibles para\n                                        la facturación de dicha contratación o futuras. De entre los fatos solicitados estarán: el nombre de cliente, dirección y NIF.\n                                        Además se le solicitará una dirección de correo email y una contraseña. Estos datos se utilizarán para darle acceso al Panel de Control desde dónde\n                                        podrá gestionar su cuenta.\n                                        <br /><br />\n                                        Una vez realizada la contratación, independientemente si ha significado un pago, la EMPRESA le enviará comunicaciones a través de email a la cuenta\n                                        de email suministrada para informarle del estado de dicha contratación y de las instrucciones para que pueda realizar las modificaciones\n                                        en su web que sean precisas.\n                                        <br /><br />\n                                        En ese momento se considerará que el cliente ha contratado el servicio, momento de entrada en vigor del presente contrato.\n                                        <br/><br/>\n                                        El cliente dispone, cuando el servicio así lo estipule en las condiciones de contratación particulares,de un plazo de prueba/demostración de 7 días\n                                        naturales durante los cuales no se emitirá factura alguna y dispondrá del servicio completo.\n                                        <br/><br/>\n                                        Una vez llegada la finalización del plazo de prueba/demostración se le enviará al cliente un mensaje email con las indicaciones para, realizar el pago \n                                        si no se hubiere hecho anteriormente. Una vez realizado el pago y comprobado la recepción del mismo el cliente podrá consultar la factura generada y\n                                        demás documentación en el Panel de Control puesto a su disposición.\n                                    </div>\n                                    <div id=\"services_withdrawal\" class=\"legal_section_title\">Derecho legal a desistir de la compra</div>\n                                    <div class=\"legal_p\">\n                                        Derecho de desistimiento\n                                        <br/><br/>\n                                        Usted está contratando como consumidor y usuario, tiene usted derecho a desistir del presente contrato en un plazo de 14 días naturales sin necesidad de justificación\n                                        <br/><br/>\n                                        Podrá desistir de aquellos servicios que no signifiquen un trabajo personalizado para un sitio web o página web en concreto ya realizado y tampoco de aquellos servicios\n                                        que su resultado sea un entregable ya entregado, por ejemplo un informe o unas modificaciónes en un documento.\n                                        <br/><br/>\n                                        El plazo de desistimiento expirará a los 14 días naturales del día que usted o un tercero por usted indicado, contrató nuestros servicios. Deberá ejercer su\n                                        derecho al desistimiento de cada servicio por separado e independientemente.\n                                        <br/><br/>\n                                        Para ejercer el derecho de desistimiento deberá notificarnos desde la dirección email suministrada como email de notificaciones nuestro email de contacto publicado en\n                                        nuestro portal.\n                                        <br/><br/>\n                                        Para cumplir el plazo de desistimiento, basta con que la comunicación relativa al ejercicio por su parte de este derecho sea enviada antes de que venza\n                                        el plazo correspondiente.\n                                        <br/><br/>\n                                        En caso de desistimiento por su parte, le devolveremos todos los pagos recibidos de usted, incluidos los gastos sin ninguna demora indebida y,\n                                        en todo caso, a más tardar en el plazo 14 días naturales a partir de la fecha en la que se nos informe de su decisión de desistir del presente contrato.\n                                        Procederemos a efectuar dicho reembolso utilizando el mismo medio de pago empleado por usted para la transacción inicial, salvo que usted nos indique lo\n                                        contrario, detallando expresamente el medio de pago a través del cual desea que realicemos la devolución. No incurrirá en ningún gasto como consecuencia del\n                                        reembolso.\n                                    </div>\n                                    <div id=\"services_offered\" class=\"legal_section_title\">Objeto y definición de los servicios ofrecidos</div>\n                                    <div class=\"legal_p\">\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L. ofrece una herramienta a través de la URL cdn.access-me.software que una vez integrada en \n                                        la web del cliente modificará esta de tal forma que le añadirá los elementos necesarios para adaptarla a las guías sobre accesibilidad reconocidas\n                                        internacionalmente. Así mismo integrará una herramienta (widged) que permitirá al usuario/visitante de la web del cliente a seleccionar uno o varios\n                                        ajustes que también modificarán la web del cliente para adaptarla a las necesidades del visitante.                                     \n                                        <br/><br/>\n                                        Por  tanto, las condiciones recogidas en este contrato serán de aplicación a los servicios/planes recogidos en la web, así mismo, este \n                                        contrato se aplicará a todo servicio/plan creado y desarrollado por Gestión y Desarrollo de Proyectos e Iniciativas, S.L. y ofrecido por la web \n                                        mielsandonis.com que reúna las características en la web de la ENTIDAD.\n                                        <br/><br/>\n                                        Las características técnicas de cada uno de estos servicios/planes, así como el precio a satisfacer por los mismos viene, en cada momento, \n                                        claramente determinado en la página de los servicios/planes correspondientes de mielsandonis.com. En todo caso los recursos y aplicaciones de que \n                                        dispone cada servicio/plan serán los que en cada  momento se encuentren publicados en la web, mielsandonis.com.\n                                        <br/><br/>\n				                        El funcionamiento de cada servicio/plan supone necesariamente disponer de la titularidad de un nombre de dominio de primer nivel genérico (gTLD) \n				                        o territorial (ccTLD). \n				                        El registro de los nombres de dominio se puede realizar a través de cualquier proveedor.\n                                        <br/><br/>                                        \n				                        Los servicios se activan con renovación automática, para desactivarla el cliente debe acceder a su Panel de control con al menos quince días (15d) \n				                        de antelación a su fecha de caducidad y solicitarlo pulsando el botón que dispone a tal efecto. Dicha renovación automática se realizará a la \n				                        fecha de caducidad.\n				                        <br/><br/>\n				                        Los costes de los planes serán los fijados en la web propiedad de la ENTIDAD en cada momento y para cada tipo de servicio/plan.\n				                        <br/><br/>\n				                        Los servicios/planes objeto de este contrato están compuestos, entre otros recursos por una herramienta denominada \"panel de control\" para cada \n				                        cliente, desde el cual el cliente puede gestionar y administrar los recursos y aplicaciones propios del servidor/plan al que haga referencia.\n				                        <br/><br/>\n				                        Se ofrece la posibilidad al cliente que tiene contratado un servicio/plan en mielsandonis.com que pueda cambiar a otro servicio/plan de mielsandonis.com \n				                        bien sea de características, recursos y aplicaciones superiores al servicio/plan del que ya dispone o inferiores.\n				                        <br/><br/>\n				                        El cambio se realizará desde el Panel de control del cliente.\n				                        <br/><br/>\n				                        Una vez realizado un cambio en los servicios/planes no se podrá solicitar otro cambio de servicio/plan en un plazo de treinta días (30d) a contar \n				                        desde que se realizó el último cambio.\n				                        <br/><br/>\n				                        Si el cambio se realiza a un plan superior en características, recursos y aplicaciones se generará un crédito o un débito por la suma pagada\n				                        y no consumida o viceversa que se le abonará o cargará en la siguiente factura que se emita al cliente según corresponda.\n                                    </div>\n                                    <div id=\"legal_updates\" class=\"legal_section_title\">Modificaciones</div>\n                                    <div class=\"legal_p\">\n                                        El portal se reserva el derecho a modificar, limitar o cancelar todos o cualquiera de los términos y condiciones aplicables \n                                        al web site referido anteriormente, siempre y cuando se realice un aviso con una antelación mínima de 15 días.\n                                        El preaviso se efectuará mediante una ventana emergente, que se abrirá al acceder a la página, o una notificación al usuario \n                                        que se realizará con carácter previo a la modificación, limitación o cancelación.\n                                        <br/><br/>\n                                        El cliente, una vez comunicada la modificación por parte de mielsandonis.com, dispone del plazo de 15 días, desde que recibe \n                                        dicha comunicación, para resolver el contrato si no estuviera de acuerdo con las nuevas circunstancias, pasado este plazo \n                                        sin comunicación en contrario del cliente se entenderá que acepta las nuevas condiciones.\n                                    </div>\n                                    <div id=\"portal_uses\" class=\"legal_section_title\">Condiciones de acceso y utilización del portal</div>\n                                    <div class=\"legal_p\">\n                                        <b>Características de la prestación ofertada</b>\n                                        <br/><br/>\n                                        El alta en los servicios/planes de mielsandonis.com y el acceso al panel de control correspondiente al servicio contratado es gratuito. \n                                        La prestación del servicio que da origen a este contrato tiene carácter oneroso, y el cliente deberá pagar por adelantado a \n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L. el precio (incluido el impuesto oportuno) correspondiente a \n                                        cada servicio determinado en la web.\n                                        <br/><br/>\n                                        La ENTIDAD emitirá la factura correspondiente con detalle de todos los conceptos que conforman dichos servicios.\n                                        <br/><br/>\n                                        Las prestaciones incluidas en cada uno de los diferentes servicios ofrecidos por la ENTIDAD, incluyendo precio, modo y \n                                        condiciones de pago, se encuentra definidos detalladamente en el sitio web.\n                                        <br/><br/>\n                                        Los servicios de pago se distinguirán de los gratuitos indicando su precio en las páginas de tarifas y servicios, \n                                        siendo condición indispensable pulsar en el icono “contratar” y rellenar el formulario de contratación que acreditará \n                                        la aceptación de las condiciones económicas.\n                                        <br/><br/>\n                                        La entidad se reserva el derecho de cobrar una tarifa adicional en caso de devolución bancaria de 5,17 euros (más IVA) o \n                                        de un 10% sobre cantidades superiores a 100 euros, y de bloquear temporalmente el acceso al Panel de control del cliente ante \n                                        cualquier incidencia en el cobro, hasta la resolución de la misma y se encuentre al corriente de pago.\n                                        <br/><br/>\n                                        En caso de no abonar la factura del servicio prestado, la empresa se reserva el derecho de incluir sus datos en ficheros \n                                        conocido como de morosidad por ejemplo el “Asnef“ de EQUIFAX IBÉRICA, S.L, los cuales serán retirados una vez verificado que \n                                        la factura ha sido pagada.\n                                        <br/><br/>\n                                        LA ENTIDAD se reserva el derecho de aplicar una penalización derivada de los gastos generados por la apertura del expediente \n                                        ídico, la cual no será superior en ningún caso a 50 euros.\n                                        <br/><br/>\n                                        Todo cliente seleccionará uno de los servicios ofertados, siendo esta operación el elemento de contratación del servicio que \n                                        lleva aparejado la obligación de registro previo.\n                                        <br/><br/>\n                                        De modo que, LA ENTIDAD podrá modificar el nombre de cliente, contraseña y código de seguridad, previo aviso al usuario vía \n                                        correo electrónico.\n                                        <br/><br/>\n                                        Los recursos y aplicaciones utilizados por del servicio contratado pueden activarse o desactivarse en cualquier momento mientras el \n                                        servicio se encuentre activo y al corriente del pago; ahora bien, si un recurso o aplicación tiene un coste mensual extra, el hecho \n                                        de desactivarlo antes de que se venza el mes pagado por adelantado no supone la devolución de la parte proporcional no consumida.\n                                        <br/><br/>\n                                        Los usuarios de servicios que no realicen la contratación estarán igualmente obligados a las condiciones reguladoras del portal.\n                                        <br/><br/>\n                                        <b>Requisitos técnicos de acceso</b>\n                                        <br/><br/>\n                                        Para acceder al Portal, el Usuario debe contar con un acceso a la Red Internet, abonar las tarifas de acceso y conexión \n                                        correspondientes y tener el equipo y los sistemas informáticos necesarios para realizar la conexión a la Red, incluyendo \n                                        un terminal que sea adecuado al efecto (ordenador, teléfono, etc.) y un módem u otro dispositivo de acceso análogo o similar.\n                                        <br/><br/>\n                                        Para el correcto acceso y uso de determinados contenidos y servicios del Portal, implica la descarga en sus equipos informáticos de \n                                        determinados programas de ordenador u otros elementos lógicos. Dicha instalación correrá a cargo del Usuario, declinando EMPRESA \n                                        cualquier tipo de responsabilidad que de ello se pudiera derivar.\n                                        <br/><br/>\n                                        <b>Obligación de hacer un uso correcto del Portal y de los Servicios</b>\n                                        <br/><br/>\n                                        El Usuario se compromete a utilizar el Portal, los Servicios, y estas Condiciones Generales de conformidad con la ley, la moral, las \n                                        buenas costumbres y el orden público.\n                                        <br/><br/>\n                                        El Usuario se obliga a abstenerse de utilizar el Portal y los Servicios con fines o efectos ilícitos, contrarios a los establecidos \n                                        en estas Condiciones Generales; lesivos de los derechos e intereses de terceros, o que de cualquier forma puedan dañar, inutilizar, \n                                        sobrecargar o deteriorar el Portal y/o los Servicios, o impedir la normal utilización o disfrute del Portal y/o de los Servicios por \n                                        parte de los Usuarios.\n                                        <br/><br/>\n                                        <b>Denegación y retirada del  acceso al Portal y/o Servicios</b>\n                                        <br/><br/>\n                                        LA ENTIDAD se reserva el derecho a denegar o retirar el acceso al Portal y/o a los Servicios, en cualquier momento y sin necesidad de \n                                        previo aviso a aquellos Usuarios que incumplan estas Condiciones Generales o infrinjan cualquiera de los preceptos establecidos por la \n                                        Ley de Servicios de la Sociedad de la Información y Comercio Electrónico (LSSICE) o legislación equivalente.\n                                        <br/><br/>\n                                        <b>Uso correcto de los Contenidos</b>\n                                        <br/><br/>\n                                        El Cliente:\n                                        <br/>\n                                        El Cliente se obliga a usar los Contenidos de forma diligente, correcta y lícita y, en particular, se compromete a abstenerse de:\n                                        <br/><br/>\n                                            Utilizar los Contenidos de forma, con fines o efectos contrarios a la ley, la moral y a las buenas costumbres generalmente \n                                            aceptadas o al orden público;\n                                        <br/><br/>\n                                            Reproducir o copiar, distribuir, permitir el acceso del público a través de cualquier modalidad de comunicación pública, \n                                            transformar o modificar los Contenidos, a menos que se cuente con la autorización del titular de los correspondientes derechos o \n                                            ello resulte legalmente permitido;\n                                        <br/><br/>\n                                            Suprimir, eludir o manipular el \"copyright\" y demás datos identificativos de los derechos de LA ENTIDAD o de sus titulares \n                                            incorporados a los Contenidos, así como los dispositivos técnicos de protección, o cualesquiera mecanismos de información que \n                                            pudieren contener los Contenidos.\n                                            <br/><br/>\n                                        El Portal:\n                                        <br/>\n                                        LA ENTIDAD, no controla ni garantiza la ausencia de virus ni de otros elementos en los Contenidos que puedan producir alteraciones en \n                                        su sistema informático (software y hardware) o en los documentos electrónicos y ficheros almacenados en su sistema informático.\n                                        <br/><br/>\n                                        <b>Uso de los Servicios</b>\n                                        <br/><br/>\n                                        El uso de los Servicios ofrecidos en el Portal de LA ENTIDAD de conformidad con la Política de Publicidad no Consentida regulada en \n                                        la Ley de Servicios de la Sociedad de la Información y Comercio Electrónico (LSSICE):\n                                        <br/><br/>\n                                        El Usuario y el Portal se obligan a hacer un uso de los Servicios conforme a la Política de Publicidad no Consentida, y en particular, \n                                        se compromete a:\n                                        <br/><br/>\n                                        No enviar cadenas de mensajes electrónicos no solicitados.\n                                        <br/><br/>\n                                        En  los  supuestos de envío publicitario por parte de LA ENTIDAD a los Usuarios se remitirá con la palabra “publicidad” para no \n                                        inducir a error.\n                                        <br/><br/>\n                                        Los Usuarios perjudicados por la recepción de mensajes no solicitados  dirigidos a una pluralidad de personas podrán comunicarlo a\n                                        LA  ENTIDAD  remitiendo un mensaje a la cuenta de correo: <a href=\"mailto:info@mielsandonis.com\" title=\"Enviar correo\">info@mielsandonis.com</a>.\n                                    </div>\n                                    <div id=\"responsibilities\" class=\"legal_section_title\">Responsabilidades</div>\n                                    <div class=\"legal_p\">\n                                        Del portal:\n                                        <br/>\n                                        No se hará responsable, además de las responsabilidades indicadas en la cláusula cuarta de las presentes condiciones \n                                        generales de uso en el portal, directa ni subsidiariamente de:\n                                        </br></br>\n                                        La calidad del servicio, la velocidad de acceso, el correcto funcionamiento ni la disponibilidad ni continuidad de \n                                        funcionamiento del portal.\n                                        </br></br>\n						                Los daños que puedan causarse en los equipos del usuario por la utilización del portal.\n                                        </br></br>\n                                        El incumplimiento de la ley, la moral y las buenas costumbres generalmente aceptadas o el orden público como \n                                        consecuencia de la transmisión, difusión, almacenamiento, puesta a disposición, recepción, obtención o acceso a los \n                                        contenidos.\n                                        </br></br>\n						                Los vicios y defectos de toda clase de los contenidos transmitidos, difundidos, almacenados o puestos a disposición.\n                                        </br></br>\n						                La ENTIDAD no es propietaria de los dominios ni de los sitios web que se encuentren en la base de datos.\n                                        </br></br>\n                                        Además, la ENTIDAD tampoco garantiza que el dominio pueda ser utilizado por el cliente sin que suponga la violación \n                                        de derechos de terceros.\n                                        </br></br>\n                                        El portal no puede garantizar que la disponibilidad del servicio sea continua e ininterrumpida durante el periodo de \n                                        vigencia del contrato, debido a la posibilidad de problemas en la red Internet, averías en los equipos servidores y \n                                        otras posibles contingencias imprevisibles.\n                                        </br></br>\n                                        El cliente acepta soportar dentro de los límites razonables riesgos e imperfecciones o indisponibilidad de los servidores, \n                                        los programas usados son técnicamente complejos y pueden que no hayan sido testados con anterioridad sobre todas las \n                                        posibilidades que existen de uso.\n                                        </br></br>\n                                        Por tanto, el cliente renuncia expresamente a reclamar cualquier responsabilidad, contractual o extracontractual, daños y \n                                        perjuicios a la ENTIDAD por posibles fallos, lentitud o errores en el acceso y uso del Servidor contratado.\n                                        </br></br>Aunque la ENTIDAD realiza copias de seguridad del contenido de los servidores utilizados para ofrecer el/los servicios, no \n                                        se responsabiliza de la pérdida o del borrado accidental de los datos. De igual manera, la ENTIDAD no garantiza la reposición total \n                                        de estos datos debido a que, en el tiempo transcurrido entre la última copia y el borrado, los datos han podido cambiar.\n                                        <br/><br/>\n                                        LA ENTIDAD no se responsabiliza:\n                                        </br></br>\n						                De los errores producidos por los proveedores de acceso.\n                                        </br></br>\n						                De la contaminación por virus en los equipos cuya protección incumbe al cliente.\n                                        </br></br>\n						                De las intrusiones de terceros en el servicio del cliente, aunque la ENTIDAD haya establecido medidas razonables de protección.\n                                        </br></br>\n						                De la configuración defectuosa por parte del cliente.\n                                        </br></br>\n						                De los deterioros de los equipos (terminales del cliente) o mal uso (responsabilidad del cliente).\n                                        </br></br>\n				                        Del cliente:\n				                        <br/><br/>\n				                        El cliente será responsable:\n                                        </br></br>\n						                De los contenidos introducidos por ellos, especialmente de los datos e informaciones introducidos en el formulario.\n                                        </br></br>\n						                De la realización de cualquier tipo de actuación ilícita, lesiva de derechos, nociva y/o perjudicial.\n                                        </br></br>\n                                        El usuario se compromete a no insertar nombres de dominios o sitios web ya existentes en la base de datos, cuyo nombre o \n                                        contenido violen las leyes vigentes.\n                                        </br></br>\n                                        El cliente se obliga a mantener operativa, activa y actualizada la dirección e-mail proporcionada en el formulario de \n                                        contratación para las comunicaciones con la ENTIDAD ya que constituye el medio de comunicación preferente para la gestión \n                                        ágil y fluida en la prestación del servicio solicitado como consecuencia de la relación contractual que a través de este \n                                        contrato nos une.\n                                    </div>\n                                    <div id=\"termination\" class=\"legal_section_title\">Terminación del contrato</div>\n                                    <div class=\"legal_p\">\n                                        El  contrato  finalizará  cuando,  además  de  las  causas  legalmente  establecidas,  concurra  alguna  de  las siguientes:\n                                        </br></br>\n					                    Mutuo Acuerdo de las partes.\n                                        </br></br>\n					                    Finalización del período inicial de duración o de las sucesivas prórrogas.\n                                        </br></br>\n					                    Resolución por incumplimiento de alguna de las partes de las obligaciones derivadas del Contrato.\n                                        </br></br>\n					                    Cuando cualquiera de las partes se encuentre en situación de quiebra o suspensión de pagos.\n                                        </br></br>\n                                        Si la resolución del contrato se debiere al incumplimiento del cliente, la ENTIDAD se reserva el derecho a terminar de forma \n                                        anticipada el presente contrato y, por lo tanto, a desposeer al cliente del servicio contratado sin  previo aviso y sin que el \n                                        cliente tenga derecho a indemnización ni a devolución de cantidad alguna.\n                                        <br/><br/>\n                                        Asimismo, si la ENTIDAD llevara a cabo un cambio en los precios de los servicios, se notificará a los clientes, vía email, tal \n                                        modificación antes de que se vean afectados por la  variación en la siguiente factura que se les emita, de manera que si no \n                                        estuviera de acuerdo en aceptar dicho cambio ejercite el derecho a resolver el presente contrato sin necesidad de pagar \n                                        cantidad adicional alguna a la ENTIDAD mientras mantenga su cuota pagada. \n                                        Al finalizar el plazo de pago por adelantado quedará resuelto el contrato y, por lo tanto, causará baja su servicio si se\n                                        mantuviera en su no aceptación al nuevo precio.\n                                    </div>\n                                    <div id=\"privacy_policy\" class=\"legal_section_title\">Política de privacidad</div>\n                                    <div class=\"legal_p\">\n                                        Responsable del Tratamiento: Gestión y Desarrollo de Proyectos e Iniciativas, S.L.\n                                        <br/><br/>\n				                        Fin del tratamiento:\n                                        <br/><br/>\n					                    Gestionar su alta como cliente, la prestación y administración del servicio de contratación y facturación.\n                                        <br/><br/>\n                                        Realización de encuestas sobre el grado de satisfacción en la atención recibida.\n                                        <br/><br/>\n					                    Remisión de publicidad y otras promociones comerciales mediante correo electrónico, SMS, MMS o cualquier otro medio análogo.\n                                        <br/><br/>\n				                        Comunicación de los datos:\n                                        <br/><br/>\n                                        No se comunicarán datos a terceros a excepción de a aquellas entidades relacionadas con Gestión y Desarrollo de Proyectos e \n                                        Iniciativas, S.L. para la correcta prestación del servicio contratado y las legalmente establecidas.\n                                        <br/><br/>\n                                        <br/><br/>\n                                        Derechos que asisten al Interesado:\n                                        <br/><br/>\n					                    Derecho a retirar el consentimiento en cualquier momento.\n                                        <br/><br/>\n					                    Derecho de acceso, rectificación, portabilidad y supresión de sus datos y a la limitación u oposición a su tratamiento.\n                                        <br/><br/>\n					                    Derecho a presentar una reclamación ante la Autoridad de control (agpd.es) si considera que el tratamiento no se ajusta a la \n					                    normativa vigente.\n                                        <br/><br/>\n				                        Datos de contacto para ejercer sus derechos:\n                                        <br/><br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.,\n                                        <br/>\n					                    C/ Padre Claret, 7, 47004 Valladolid o a través de correo electrónico a <a href=\"mailto:juridico@mielsandonis.com\" title=\"Enviar correo\">juridico@mielsandonis.com</a>, \n					                    junto con prueba válida en derecho, como fotocopia del D.N.I. e indicando en el asunto \"PROTECCIÓN DE DATOS\".\n					                    <br/><br/>\n					                    Información adicional: Documento “Información adicional Protección de Datos” disponible en nuestra web \n					                    <a href=\"https://www.mielsandonis.com\" title=\"Inicio mielsandonis\">https://mielsandonis.com</a>.\n					                    <br/><br/>\n					                    El interesado consiente al tratamiento de los datos en los términos expuestos.\n                                    </div>\n                                    <div id=\"third_parties\" class=\"legal_section_title\">¿Qué ocurre si el servicio contratado supone un acceso por cuenta de terceros?</div>\n                                    <div class=\"legal_p\">\n                                        Si para la prestación de los servicios contratados a través de la web y, en concreto en lo que al tratamiento de los datos del \n                                        personal del cliente se refiere, Gestión y Desarrollo de Proyectos e Iniciativas, S.L. ostenta la figura de \n                                        ENCARGADO DEL TRATAMIENTO y la de RESPONSABLE DEL TRATAMIENTO.\n                                        <br/><br/>\n                                        Que en cumplimiento de lo dispuesto en el artículo 28 del GDPR, el ENCARGADO ofrece suficientes garantías para implementar \n                                        políticas técnicas y organizativas apropiadas para aplicar las medidas de seguridad que establece la normativa vigente y proteger \n                                        los derechos de los interesados, por lo cual ambas partes convienen suscribir el presente contrato con sujeción a las  siguientes  \n                                        INSTRUCCIONES PARA EL TRATAMIENTO DE DATOS:\n                                        <br/><br/>\n                                        El tratamiento consistirá en los servicios de añadir accesibilidad a las webs de los clientes.\n                                        <br/><br/>\n                                        Concretamente se realizarán los siguientes tratamientos:\n                                        <br/><br/>\n                                        Para la ejecución de las prestaciones derivadas del cumplimiento del objeto de este encargo, el responsable del tratamiento, \n                                        puede poner a disposición del encargado del tratamiento, datos de carácter personal.\n                                        <br/><br/>\n                                        El encargado del tratamiento y todo su personal se obliga a:\n                                        <br/><br/>\n                                        Utilizar los datos personales objeto de tratamiento, o los que recoja para su inclusión, sólo para la finalidad objeto de este encargo.\n					                    En ningún caso podrá utilizar los datos para fines propios.\n                                        <br/><br/>\n                                        Tratar los datos de acuerdo con las instrucciones del responsable del tratamiento. Si el encargado del tratamiento considera que alguna \n                                        de las instrucciones infringe el RGPD o cualquier otra disposición en materia de protección de datos de la Unión o de los Estados \n                                        miembros, el encargado informará inmediatamente al responsable.\n                                        <br/><br/>\n                                        No comunicar los datos a terceras personas, salvo que cuente con la autorización expresa del responsable del tratamiento, en los \n                                        supuestos legalmente admisibles.\n                                        <br/><br/>\n                                        No subcontratar ninguna de las prestaciones que formen parte del objeto de este contrato que comporten el tratamiento de datos \n                                        personales, salvo los servicios auxiliares necesarios para el normal funcionamiento de los servicios del encargado. \n                                        Si fuera necesario subcontratar algún  tratamiento, este hecho se deberá comunicar previamente y por escrito al responsable, con una \n                                        antelación de 15 días, indicando los tratamientos que se pretende subcontratar e identificando de forma clara e inequívoca la empresa \n                                        subcontratista y sus datos de contacto. La subcontratación podrá llevarse a cabo si el responsable no manifiesta su oposición en el \n                                        plazo establecido. El subcontratista, que también tendrá la condición de encargado del tratamiento, está obligado igualmente a cumplir \n                                        las obligaciones establecidas en este documento para el encargado del tratamiento y las instrucciones que dicte el responsable.\n                                        Corresponde al  encargado inicial regular la nueva relación de forma que el nuevo encargado quede sujeto a las mismas condiciones \n                                        (instrucciones, obligaciones, medidas de seguridad...) y con los mismos requisitos formales que él, en lo referente al adecuado \n                                        tratamiento de los datos personales y a la garantía de los derechos de las personas afectadas. \n                                        En el caso de incumplimiento por parte del subencargado, el encargado inicial seguirá siendo plenamente responsable ante el responsable \n                                        en lo referente al cumplimiento de las obligaciones.\n                                        <br/><br/>\n                                        Mantener el deber de secreto respecto a los datos de carácter personal a los que haya tenido acceso en virtud del presente encargo, \n                                        incluso después de que finalice su objeto.\n                                        <br/><br/>\n                                        Garantizar que las personas autorizadas para tratar datos personales se comprometan, de forma expresa y por escrito, a respetar la \n                                        confidencialidad y a cumplir las medidas de seguridad correspondientes, de las que hay que informarles convenientemente.\n                                        <br/><br/>\n                                        Mantener a disposición del responsable la documentación acreditativa del cumplimiento de la obligación establecida en el apartado \n                                        anterior.\n                                        <br/><br/>\n                                        Garantizar la formación necesaria en materia de protección de datos personales de las personas autorizadas para tratar datos personales.\n                                        <br/><br/>\n                                        Cuando  las  personas  afectadas ejerzan los derechos de acceso, rectificación, supresión y oposición, limitación del tratamiento, \n                                        portabilidad de datos y a no ser objeto de decisiones individualizadas automatizadas, ante el encargado del tratamiento, éste debe \n                                        comunicarlo por correo electrónico a la dirección de contacto entre ambas empresas. La comunicación debe hacerse de forma inmediata \n                                        y en  ningún caso más allá del día laborable siguiente al de la recepción de la solicitud, juntamente, en su caso, con otras \n                                        informaciones que  puedan ser relevantes para resolver la solicitud.\n                                        <br/><br/>\n                                        Derecho de información. Corresponde al responsable facilitar el derecho de información en el momento de la recogida de los datos.\n                                        <br/><br/>\n                                        Notificación de violaciones de la seguridad de los datos. El encargado del tratamiento notificará al responsable del tratamiento, \n                                        sin dilación indebida, y en cualquier caso antes del plazo máximo de 24 horas, y a través del correo electrónico de contacto entre \n                                        ambas empresas, las violaciones de la seguridad de los datos personales a su cargo de las que tenga conocimiento, juntamente con toda \n                                        la información relevante para la documentación y comunicación de la incidencia. \n                                        No será necesaria la notificación cuando sea improbable que dicha violación de la seguridad constituya un riesgo para los derechos y \n                                        las libertades de las personas físicas.\n                                        <br/><br/>\n                                        Si se dispone de ella se facilitará, como mínimo, la información siguiente:\n                                        <br/><br/>\n                                        Descripción de la naturaleza de la violación de la seguridad de los datos personales, inclusive, cuando sea posible, las categorías \n                                        y el número aproximado de interesados afectados, y las categorías y el número aproximado de registros de datos personales afectados.\n                                        <br/><br/>\n                                        El nombre y los datos de contacto del delegado de protección de datos o de otro punto de contacto en el que pueda obtenerse más \n                                        información.\n                                        <br/><br/>\n                                        Descripción de las posibles consecuencias de la violación de la seguridad de los datos personales.\n                                        <br/><br/>\n                                        Descripción de las medidas adoptadas o propuestas para poner remedio a la violación de la seguridad de los datos personales, \n                                        incluyendo, si procede, las medidas adoptadas para  mitigar los posibles efectos negativos. Si no es posible facilitar la \n                                        información simultáneamente, y en la medida en que no lo sea, la información se facilitará de manera gradual sin dilación indebida.\n                                        <br/><br/>\n                                        Dar apoyo al responsable del tratamiento en la realización de las evaluaciones de impacto relativas a la protección de datos, \n                                        cuando proceda.\n                                        <br/><br/>\n                                        Dar apoyo al responsable del tratamiento en la realización de las consultas  previas a la autoridad de control, cuando proceda.\n                                        <br/><br/>\n                                        Poner disposición del responsable toda la información necesaria para demostrar el cumplimiento de sus obligaciones, así como para la \n                                        realización de las auditorías o las inspecciones que realicen el responsable u otro auditor autorizado por él.\n                                        <br/><br/>\n                                        Implantar las medidas de seguridad siguientes (en función del servicio contratado):\n                                        <br/><br/>\n                                        Clasificación de incidentes de seguridad con sus correspondientes tiempos de respuesta y recuperación según requisitos de ISO 27001.\n                                        <br/><br/>\n                                        Mecanismos de backup, tolerancia a fallos y tiempos de recuperación.\n                                        <br/><br/>\n                                        Planes de continuidad de negocio antes desastres naturales.\n                                        <br/><br/>\n                                        Organización y estructura de centros de datos dispone de redundancias a nivel de almacenamiento, procesamiento, red y alimentación \n                                        eléctrica.\n                                        <br/><br/>\n                                        Medidas de control de acceso físico y lógico y mecanismos de autenticación.\n                                        <br/><br/>\n                                        Escaneos de vulnerabilidades en servicios administrados y en equipos que formen parte de infraestructura con regularidad.\n                                        <br/><br/>\n                                        Procedimientos seguros de acceso a la interface, con métodos de autenticación, restricciones de acceso y privilegios.\n                                        <br/><br/>\n                                        En caso de incidente de seguridad es posible rastrear el mismo mediante los adecuados procedimientos de monitorización.\n                                        <br/><br/>\n                                        Los centros de datos se encuentran ubicados en la Unión Europea.<br/><br/>\n                                        <br/><br/>\n                                        En todo caso, deberá implantar mecanismos para:\n                                        <br/><br/>\n                                        Garantizar la confidencialidad, integridad, disponibilidad y resiliencia permanentes de los sistemas y servicios de tratamiento.\n                                        <br/><br/>\n                                        Restaurar la disponibilidad y el acceso a los datos personales de forma rápida, en caso de incidente físico o técnico.\n                                        <br/><br/>\n                                        Verificar, evaluar y valorar, de forma regular, la eficacia de las medidas técnicas y organizativas implantadas para garantizar la \n                                        seguridad del tratamiento.\n                                        <br/><br/>\n                                        Seudonimizar y cifrar los datos personales, en su caso.\n                                        <br/><br/>\n                                        Destruir los datos, una vez cumplida la prestación. No obstante, el encargado puede conservar una copia, con los datos debidamente \n                                        boqueados, mientras puedan derivarse responsabilidades de la ejecución de la prestación.\n                                    </div>\n                                    <div id=\"property_intellectual\" class=\"legal_section_title\">Propiedad intelectual e industrial</div>\n                                    <div class=\"legal_p\">\n                                        La totalidad de esta web: texto, imágenes, marcas, gráficos, logotipos, botones, archivos de software, combinaciones de colores, \n                                        así como la estructura, selección, ordenación y presentación de sus contenidos, se encuentra protegida por las leyes sobre Propiedad \n                                        Intelectual e Industrial, quedando prohibida su reproducción, distribución, comunicación pública y transformación, \n                                        salvo para uso personal y privado.\n                                        <br/><br/>\n                                        Así mismo, queda prohibida la reproducción, retransmisión, copia, cesión o redifusión, total o parcial, de la información contenida \n                                        en estas páginas, cualquiera que fuera su finalidad y el medio utilizado para ello.\n                                    </div>\n                                    <div id=\"cookie\" class=\"legal_section_title\">Uso de tecnología cookies y almacenamiento en el navegador</div>\n                                    <div class=\"legal_p\">\n                                        LA ENTIDAD se reserva el derecho de utilización de las denominadas “cookies” y otras tecnologías de almacenamiento de \n                                        información, en cualquier tipo de utilización del Portal.\n                                        <br/><br/> \n                                        No obstante, se informa a los Usuarios de la posibilidad de desechar esa utilización en su terminal informático.\n                                        <br/><br/>\n                                        <br/><br/>\n                                        Gestión y Desarrollo de Proyectos e Iniciativas, S.L.                                      \n                                        C/ Padre Claret, 7, 47004 Valladolid Telf: 983 10 59 08  http://mielsandonis.com\n                                    </div>');
INSERT INTO `lang_text_name` (`id`, `lang_text`, `lang_code_2a`, `lang_variant`, `text`) VALUES
(33, 17, 'en', NULL, 'legal-stuff'),
(34, 17, 'es', NULL, 'aviso-legal'),
(35, 18, 'en', NULL, 'sales-terms'),
