(38, 19, 'es', NULL, 'politica-privacidad'),
(39, 20, 'en', NULL, 'cookies-policy'),
(40, 20, 'es', NULL, 'politica-cookies'),
(41, 21, 'en', NULL, 'payment-terms'),
