(44, 22, 'es', NULL, 'declaracion-accesibilidad'),
(45, 23, 'en', NULL, 'Accessibility Statement'),
(46, 23, 'es', NULL, 'Declaracion de Accesibilidad'),
(47, 24, 'en', NULL, 'This is our Accessibility Statement'),
(48, 24, 'es', NULL, 'Conozca nuestra Declaración de Accesibilidad'),
(49, 25, 'en', NULL, 'Accessibility Statement'),
