(50030, 50014, 'en', NULL, 'Free your team from repetitive, low-value, high-cost tasks.'),
(50031, 50014, 'es', NULL, 'Liberar a tu equipo de las tareas repetitivas de bajo valor y alto coste.'),
(50032, 50015, 'en', NULL, 'It allows you to focus on more strategic and creative activities.'),
(50033, 50015, 'es', NULL, 'Permite enfocarte en actividades más estratégicas y creativas.'),
(50034, 50016, 'en', NULL, 'This not only saves time but also resources; time is money.'),
