(50046, 50022, 'en', NULL, 'By controlling the processes where errors are common, you ensure greater reliability in the results.'),
(50047, 50022, 'es', NULL, 'Controlas los procesos donde los errores son comunes, aseguras una mayor fiabilidad en los resultados.'),
(50048, 50023, 'en', NULL, 'Strengthen neglected areas'),
(50049, 50023, 'es', NULL, 'Potencia áreas relegadas'),
(50050, 50024, 'en', NULL, 'Time is what it is, and you can\'t do everything.'),
(50051, 50024, 'es', NULL, 'El tiempo es el que es y a todo no llegas.'),
(50052, 50025, 'en', NULL, 'Automating tasks frees up your time and allows you to dedicate yourself to tasks you couldn\'t do before.'),
