(50068, 50033, 'en', NULL, 'Focus on strategic tasks and let automation take care of the rest.'),
(50069, 50033, 'es', NULL, 'Dedícate a tareas estratégicas y deja que la automatización se ocupe del resto.'),
(50070, 50034, 'en', NULL, 'Full customization'),
(50071, 50034, 'es', NULL, 'Personalización total'),
(50072, 50035, 'en', NULL, 'Solutions designed to meet your goals and needs.'),
(50073, 50035, 'es', NULL, 'Soluciones diseñadas a la medida de tus objetivos y necesidades.'),
