(50080, 50039, 'en', NULL, 'We create optimized solutions for you. Privacy and security guaranteed.'),
(50081, 50039, 'es', NULL, 'Creamos soluciones optimizadas para ti. Privacidad y seguridad aseguradas.'),
(50082, 50040, 'en', NULL, 'Implementation and monitoring'),
(50083, 50040, 'es', NULL, 'Implementación y seguimiento'),
(50084, 50041, 'en', NULL, 'A smooth transition to the new situation, we guarantee success.'),
(50085, 50041, 'es', NULL, 'Transición fluída a la nueva situación, garantizamos el éxito.'),
(50086, 50042, 'en', NULL, 'Frequently Asked Questions (FAQ) about Automation with AI'),
(50087, 50042, 'es', NULL, 'Preguntas Frecuentes (FAQ) sobre la Automatización con IA'),
(50088, 50043, 'en', NULL, 'What types of tasks can I automate with Artificial Intelligence (AI)?'),
(50089, 50043, 'es', NULL, '¿Qué tipo de tareas puedo automatizar con Inteligencia Artificial (IA)?'),
(50090, 50044, 'en', NULL, 'Virtually any task that is <strong>repetitive, manual, or follows defined patterns</strong>.</p>'),
(50091, 50044, 'es', NULL, 'Prácticamente cualquier tarea <strong>repetitiva, manual o que siga patrones definidos</strong>.</p>'),
(50092, 50045, 'en', NULL, 'This includes:'),
(50093, 50045, 'es', NULL, 'Esto incluye:'),
(50094, 50046, 'en', NULL, '<strong>Marketing:</strong> Content generation, email flows, <em>chatbots</em> support, lead management.'),
(50095, 50046, 'es', NULL, '<strong>Marketing:</strong> Generación de contenido, flujos de email, atención con <em>chatbots</em>, gestión de leads.'),
(50096, 50047, 'en', NULL, '<strong>Internal Management:</strong> Billing, data analysis, <em>stock</em> control, report generation, document classification, and scheduling.'),
(50097, 50047, 'es', NULL, '<strong>Gestión interna:</strong> Facturación, análisis de datos, control de <em>stock</em>, generación de informes, clasificación de documentos, coordinación de agendas.'),
(50098, 50048, 'en', NULL, '<strong>Customer/Public Service:</strong> Appointment management, telephone support, and resolving queries.'),
(50099, 50048, 'es', NULL, '<strong>Atención al público/clientes:</strong> Gestión de citas, atención telefónica, resolución de consultas.'),
(50100, 50049, 'en', NULL, '<strong>Internal communication:</strong> Consultation of procedure manuals, onboarding.'),
(50101, 50049, 'es', NULL, '<strong>Comunicación interna:</strong> Consulta de manuales de procedimiento, onboarding.'),
(50102, 50050, 'en', NULL, 'The key is to free your team from time-consuming tasks that do not generate strategic value.'),
(50103, 50050, 'es', NULL, 'La clave es liberar a tu equipo de tareas que consumen tiempo y no generan valor estratégico.'),
(50104, 50051, 'en', NULL, 'How do I know if my business is ready for AI and automations from Altira Automations?'),
(50105, 50051, 'es', NULL, '¿Cómo sé si mi negocio está listo para la IA y las automatizaciones de Altira Automations?'),
(50106, 50052, 'en', NULL, '<strong>Your business is more than ready if you identify any of these points:</strong>'),
(50107, 50052, 'es', NULL, '<strong>Tu negocio está más que listo si identificas cualquiera de estos puntos:</strong>'),
(50108, 50053, 'en', NULL, 'You dedicate a significant amount of time to <strong>manual, repetitive, or routine tasks</strong>.'),
(50109, 50053, 'es', NULL, 'Dedicáis una cantidad significativa de tiempo a <strong>tareas manuales, repetitivas o rutinarias</strong>.'),
(50110, 50054, 'en', NULL, 'You need to  <strong>scale</strong> your operations and workload without making large, immediate hires.'),
(50111, 50054, 'es', NULL, 'Necesitas <strong>escalar</strong> tus operaciones y volumen de trabajo sin hacer grandes contrataciones inmediatas.'),
(50112, 50055, 'en', NULL, 'You manage or generate <strong>large amounts of data</strong> that must be processed or analyzed.'),
(50113, 50055, 'es', NULL, 'Gestionáis o generáis <strong>grandes cantidades de datos</strong> que deben ser procesados o analizados.'),
(50114, 50056, 'en', NULL, 'You seek to <strong>reduce the margin of error</strong> in critical processes.'),
(50115, 50056, 'es', NULL, 'Buscas <strong>reducir el margen de error</strong> en procesos críticos.'),
(50116, 50057, 'en', NULL, 'What\'s important is the  <strong>willingness to change</strong>. At <span class=\"highlight\">Altira Automations</span>, <strong>we don\'t require an advanced technological infrastructure</strong>. We carry out the diagnosis, design the solution <em>perfectly adapted to your reality</em>, and provide you with a progressive and easy plan for a quick and cost-effective transition.'),
(50117, 50057, 'es', NULL, 'Lo importante es la <strong>disposición al cambio</strong>. En <span class=\"highlight\">Altira Automations</span>, <strong>no exigimos una estructura tecnológica avanzada</strong>. Nosotros hacemos el diagnóstico, diseñamos la solución <em>perfectamente adaptada a tu realidad</em> y te proporcionamos un plan progresivo y fácil para una transición rápida y rentable.'),
(50118, 50058, 'en', NULL, 'What is the difference between traditional automation and automation that uses AI?'),
(50119, 50058, 'es', NULL, '¿Qué diferencia hay entre la automatización tradicional y la que usa IA?'),
(50120, 50059, 'en', NULL, 'Traditional automation follows fixed, programmed rules. AI automation goes further:  <strong>It learns from data, identifies patterns, predicts</strong>, and makes intelligent decisions. For example, AI sends an email at the optimal time detected for each user, not at a fixed time.'),
(50121, 50059, 'es', NULL, 'La automatización tradicional sigue reglas fijas programadas. La automatización con IA va más allá: <strong>Aprende de los datos, identifica patrones, predice</strong> y toma decisiones inteligentes. Por ejemplo, la IA envía un email en el momento óptimo detectado para cada usuario, no a una hora fija.'),
(50122, 50060, 'en', NULL, 'Is AI suitable for any type of business?'),
(50123, 50060, 'es', NULL, '¿La IA es adecuada para cualquier tipo de negocio?'),
(50124, 50061, 'en', NULL, '<strong>Yes.</strong> We adapt AI solutions to the specific needs of any company, whether it\'s an  <em>ecommerce</em>, an established brand, or a local business.'),
(50125, 50061, 'es', NULL, '<strong>Sí.</strong> Adaptamos las soluciones de IA a las necesidades específicas de cualquier empresa, ya sea una <em>ecommerce</em>, una marca consolidada o un negocio local.'),
(50126, 50062, 'en', NULL, 'Can AI completely replace the work of my team?'),
(50127, 50062, 'es', NULL, '¿La IA puede sustituir completamente el trabajo de mi equipo?'),
(50128, 50063, 'en', NULL, '<strong>No.</strong> AI does not replace  <strong>human creativity, strategy, or empathy</strong>.  Its role is to act as an  <strong>efficient assistant</strong> that handles operational tasks, allowing your team to focus on growth.'),
(50129, 50063, 'es', NULL, '<strong>No.</strong> La IA no reemplaza la <strong>creatividad, la estrategia o la empatía humana</strong>. Su función es actuar como un <strong>asistente eficiente</strong> que se encarga de las tareas operativas, permitiendo que tu equipo se centre en el crecimiento.'),
(50130, 50064, 'en', NULL, 'What is the difference between a specific AI agent and generalist tools like ChatGPT?'),
(50131, 50064, 'es', NULL, '¿Qué diferencia hay entre un agente IA específico y herramientas generalistas como ChatGPT?'),
(50132, 50065, 'en', NULL, 'An  <strong>AI Agent</strong> is <strong> trained specifically for your business</strong>, your data, and your specific goals, automating tasks with a focus on your niche.  Tools like ChatGPT are broad and general-purpose language models.'),
(50133, 50065, 'es', NULL, 'Un <strong>Agente IA</strong> está <strong>entrenado específicamente para tu negocio</strong>, tus datos y tus objetivos concretos, automatizando tareas con un enfoque en tu nicho. Herramientas como ChatGPT son modelos de lenguaje amplios y generalistas.'),
(50134, 50066, 'en', NULL, 'How do I know if my company is ready to implement AI?'),
(50135, 50066, 'es', NULL, '¿Cómo sé si mi empresa está lista para implementar IA?'),
(50136, 50067, 'en', NULL, 'If your company spends hours on manual tasks, manages large volumes of data, or is looking to scale without rapidly increasing staff, you\'re ready. You don\'t need an advanced technological infrastructure, just the willingness to integrate new solutions.'),
(50137, 50067, 'es', NULL, 'Si tu empresa dedica horas a tareas manuales, gestiona grandes volúmenes de datos, o busca escalar sin aumentar la plantilla rápidamente, está lista. No necesitas una estructura tecnológica avanzada, solo la disposición para integrar nuevas soluciones.'),
(50138, 50068, 'en', NULL, 'Do I need technical or programming knowledge to use automations?'),
(50139, 50068, 'es', NULL, '¿Necesito conocimientos técnicos o de programación para usar las automatizaciones?'),
(50140, 50069, 'en', NULL, '<strong>No.</strong> Our goal is to make technology work for you. We design and implement easy-to-manage solutions and provide you with the necessary training. We can also handle the management and monitoring if you prefer.'),
(50141, 50069, 'es', NULL, '<strong>No.</strong> Nuestro objetivo es que la tecnología trabaje para ti. Diseñamos e implementamos soluciones fáciles de gestionar y te proporcionamos la formación necesaria. También podemos encargarnos de la gestión y monitorización si lo prefieres.'),
(50142, 50070, 'en', NULL, 'Can I integrate these AI solutions with the systems I already use (CRM, CMS, etc.)?'),
(50143, 50070, 'es', NULL, '¿Puedo integrar estas soluciones de IA con los sistemas que ya utilizo (CRM, CMS, etc.)?'),
(50144, 50071, 'en', NULL, '<strong>In most cases, yes.</strong> We evaluate your current tools and look for seamless integrations so that all your systems work together.'),
(50145, 50071, 'es', NULL, '<strong>En la mayoría de los casos, sí.</strong> Evaluamos tus herramientas actuales y buscamos integraciones fluidas para que todos tus sistemas trabajen conjuntamente.'),
(50146, 50072, 'en', NULL, 'How long does it take to implement AI automation?'),
(50147, 50072, 'es', NULL, '¿Cuánto tiempo se tarda en implementar una automatización con IA?'),
(50148, 50073, 'en', NULL, '<strong>Simple projects</strong> (e.g., <em>chatbot</em> or <em>email marketing</em> flow): <strong>A few days</strong>.'),
(50149, 50073, 'es', NULL, '<strong>Proyectos sencillos</strong> (ej. <em>chatbot</em> o flujo de <em>email marketing</em>): <strong>Pocos días</strong>.'),
(50150, 50074, 'en', NULL, '<strong>Complex projects</strong> (e.g., CRM integration, document management): <strong>2 to 6 weeks</strong>.'),
(50151, 50074, 'es', NULL, '<strong>Proyectos complejos</strong> (ej. integración de CRM, gestión documental): <strong>2 a 6 semanas</strong>.'),
(50152, 50075, 'en', NULL, 'We always provide you with a clear timeline from the start.'),
(50153, 50075, 'es', NULL, 'Siempre te proporcionamos un cronograma claro desde el inicio.'),
(50154, 50076, 'en', NULL, 'How does AI protect my company\'s and my customers\' sensitive data?'),
(50155, 50076, 'es', NULL, '¿Cómo protege la IA los datos sensibles de mi empresa y mis clientes?'),
(50156, 50077, 'en', NULL, 'We develop platforms that comply with <strong>high-level security protocols and regulations such as GDPR</strong>. We configure restricted access, dedicated servers, and offer cybersecurity recommendations for your team.'),
(50157, 50077, 'es', NULL, 'Desarrollamos plataformas que cumplen con <strong>protocolos de seguridad de alto nivel y normativas como GDPR</strong>. Configuramos accesos limitados, servidores dedicados y ofrecemos recomendaciones de ciberseguridad para tu equipo.'),
(50158, 50078, 'en', NULL, 'How much does it cost to implement AI automation in my business?'),
(50159, 50078, 'es', NULL, '¿Cuánto cuesta implementar automatizaciones con IA en mi negocio?'),
(50160, 50079, 'en', NULL, 'The cost is <strong>variable</strong> and depends on complexity and volume. The investment is generally <strong>low</strong> compared to the cost of additional staff and is quickly recovered. We work with <strong>scalable plans</strong> for affordable budgets.'),
(50161, 50079, 'es', NULL, 'El coste es <strong>variable</strong> y depende de la complejidad y el volumen. La inversión es generalmente <strong>baja</strong> en comparación con el coste de personal adicional y se recupera rápidamente. Trabajamos con <strong>planes escalables</strong> para presupuestos accesibles.'),
(50162, 50080, 'en', NULL, 'How do I start automating processes with AI in my business?'),
(50163, 50080, 'es', NULL, '¿Cómo empiezo a automatizar procesos con IA en mi negocio?'),
(50164, 50081, 'en', NULL, 'The first step is our <a href=\"#index_free_audit\"><strong>free diagnostic</strong></a>. We analyze your processes, identify time-consuming tasks, and design an automation plan. It\'s a guided process through to final integration.'),
(50165, 50081, 'es', NULL, 'El primer paso es nuestro <a href=\"#index_free_audit\"><strong>diagnóstico gratuito</strong></a>. Analizamos tus procesos, identificamos tareas que consumen tiempo y diseñamos un plan de automatización. Es un proceso guiado hasta la integración final.'),
(50166, 50082, 'en', NULL, 'What specific guarantees does Altira Automations offer in the implementation of its AI solutions?'),
(50167, 50082, 'es', NULL, '¿Qué garantías concretas ofrece Altira Automations en la implementación de sus soluciones de IA?'),
(50168, 50083, 'en', NULL, 'At <strong>Altira Automations</strong>, our guarantee focuses on two pillars: <strong>Results and Long-Term Support</strong>.'),
(50169, 50083, 'es', NULL, 'En <strong>Altira Automations</strong>, nuestra garantía se centra en dos pilares: <strong>Resultados y Soporte a Largo Plazo</strong>.'),
(50170, 50084, 'en', NULL, '<strong>Goal Achievement and ROI:</strong> We work under a clear objectives agreement. We guarantee that the implemented solution will achieve the efficiency or time-saving results we defined with you in the initial plan. Automation is a strategic investment with a measurable return.'),
(50171, 50084, 'es', NULL, '<strong>Cumplimiento de Objetivos y ROI:</strong> Trabajamos bajo un acuerdo de objetivos claros. Garantizamos que la solución implementada alcanzará los resultados de eficiencia o ahorro de tiempo que hemos definido contigo en el plan inicial. La automatización es una inversión estratégica con un retorno medible.'),
(50172, 50085, 'en', NULL, '<strong>Ongoing Support and Optimization:</strong> We offer ongoing <strong>technical support and consulting</strong> to resolve any issues and ensure your automation remains optimal, scalable, and adaptable to any changes in your business or the market. If a problem arises, we\'re there to solve it.'),
(50173, 50085, 'es', NULL, '<strong>Soporte Continuo y Optimización:</strong> Ofrecemos <strong>soporte técnico y consultoría continua</strong> para resolver cualquier incidencia y asegurarnos de que la automatización se mantenga óptima, escalable y adaptada a cualquier cambio en tu negocio o en el mercado. Si surge un problema, estamos ahí para solucionarlo.'),
(50174, 50086, 'en', NULL, '<strong>Confidentiality and Security:</strong> We guarantee that all automations are implemented under the highest security and regulatory compliance protocols (GDPR), protecting your data and that of your customers at all times.'),
(50175, 50086, 'es', NULL, '<strong>Confidencialidad y Seguridad:</strong> Garantizamos que todas las automatizaciones se implementan bajo los más altos protocolos de seguridad y cumplimiento normativo (GDPR), protegiendo tus datos y los de tus clientes en todo momento.'),
(50176, 50087, 'en', NULL, 'What happens if an automation doesn\'t meet my expectations?'),
(50177, 50087, 'es', NULL, '¿Qué sucede si una automatización no cumple con mis expectativas?'),
(50178, 50088, 'en', NULL, 'We work continuously with you to make  <strong>adjustments and optimizations</strong> until the desired results and agreed-upon objectives are achieved. We offer ongoing support to ensure effectiveness.'),
(50179, 50088, 'es', NULL, 'Trabajamos de forma continua contigo para realizar <strong>ajustes y optimizaciones</strong> hasta que se alcancen los resultados deseados y los objetivos acordados. Ofrecemos soporte continuo para garantizar la efectividad.'),
(50180, 50089, 'en', NULL, 'Where do I begin?'),
(50181, 50089, 'es', NULL, '¿Por dónde empiezo?'),
(50182, 50090, 'en', NULL, 'We offer you a FREE initial audit');
