(50288, 50143, 'en', NULL, 'We work with you to automate what\'s holding you back'),
(50289, 50143, 'es', NULL, 'Trabajamos contigo para automatizar lo que te frena'),
(50290, 50144, 'en', NULL, 'We\'re the AI experts who sit down with you to understand your business'),
(50291, 50144, 'es', NULL, 'Somos los expertos en IA que se sientan a entender tu negocio'),
(50292, 50145, 'en', NULL, 'We understand the frustration of wasting hours on emails, calendars, or administrative tasks. Our team doesn\'t just implement technology; we use it to tackle inefficiencies, free up your people, and ensure every process is as profitable as it should be.  <b>As profitable as it should be</b>.'),
(50293, 50145, 'es', NULL, 'Entendemos la frustración de perder horas en correos, agendas o tareas de gestión. Nuestro equipo no solo implementa la tecnología; la usamos para atacar la ineficiencia, liberar a tu gente y garantizar que cada proceso sea <b>tan rentable como debería ser</b>.'),
